INSERT INTO `recipe_step` (`step_id`, `recipe_id`, `step_number`, `description`, `image_url`) VALUES (1674,331,1,'손질된 새우를 끓는 물에 데쳐 건진다.a','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00028_1.png'),(1675,331,2,'연두부, 달걀, 생크림, 설탕에 녹인 무염버터를 믹서에 넣고 간 뒤 새우(1)를 함께 섞어 그릇에 담는다.b','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00028_2.png'),(1676,331,3,'시금치를 잘게 다져 혼합물 그릇(2)에 뿌리고 찜기에 넣고 중간 불에서 10분 정도 찐다.c','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00028_3.png'),(1677,332,1,'부추는 깨끗이 씻어 물기를 제거하고, 5cm 길이로 썰고 부추에 날콩가루를 넣고 고루 섞이도록 버무린다.','http://www.foodsafetykorea.go.kr/uploadimg/20230206/20230206054820_1675673300714.jpg'),(1678,332,2,'찜기에 면보를 깔고 부추를 넣은 후 김이 오르게 쪄서 파랗게 익힌다.','http://www.foodsafetykorea.go.kr/uploadimg/20230206/20230206054834_1675673314720.jpg'),(1679,332,3,'저염간장에 다진 대파, 다진 마늘, 고춧가루, 요리당 , 참기름, 참깨를 섞어 양념장을 만들고 찐 부추는 그릇에 담아낸다.','http://www.foodsafetykorea.go.kr/uploadimg/20230206/20230206054908_1675673348152.jpg'),(1680,333,1,'물기를 빼고 2cm 정도의 크기로 썰은 부추와 양파를 양념장에 섞어 양념속을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00031_1.png'),(1681,333,2,'깨끗이 씻은 방울토마토는 꼭지를 떼고 윗부분에 칼로 십자모양으로 칼집을 낸다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00031_4.png'),(1682,333,3,'칼집을 낸 방울토마토에 양념속을 사이사이에 넣어 버무린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00031_5.png'),(1683,334,1,'사과, 순두부를 믹서에 넣고 곱게 갈아 소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00032_1.png'),(1684,334,2,'오이는 소금으로 문질러 씻어 반을 갈라 씨를 제거하고 어슷썰기를 한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00032_2.png'),(1685,334,3,'썰어 놓은 오이에 순두부사과 소스를 넣고 버무린 후 다진 땅콩을 뿌려 마무리 한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00032_3.png'),(1686,335,1,'북어채를 잘게 손으로 찢어 찬물에 헹구어 준비한 후 양파, 표고버섯, 사과는 채 썰고 새우는 등쪽의 두세 마디에 꼬챙이를 넣어 내장을 뺀 후 헹군다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00033_2.png'),(1687,335,2,'찬물에 북어채, 새우, 표고버섯, 양파를 넣고 20분 정도 끓인 후 사과를 넣어 북어의 씁쓸한 맛을 없앤다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00033_3.png'),(1688,335,3,'그릇에 담아낸다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00033_5.png'),(1689,336,1,'황태는 손질하여 물에 헹궈 건져 놓고 콩나물은 다듬어 씻고 청양고추는 어슷썰기 한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00036_3.png'),(1690,336,2,'냄비에 물을 붓고 황태와 무를 넣고 끓인 후 육수에서 물을 건져내고 저염 된장을 푼다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00036_4.png'),(1691,336,3,'콩나물, 다진 마늘, 청양고추를 넣고 뚜껑을 덮어 김이 나게 끓\n여준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00036_5.png'),(1692,337,1,'감자, 양파는 얇게 썰고 애느타리 버섯은 썰어 달궈진 팬에 굽는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00037_2.png'),(1693,337,2,'냄비에 물을 붓고 된장을 푼 뒤 감자, 양파, 두부를 넣어 재료가 투명해지게 끓인 후 된장국의 재료를 건져서 믹서에 넣어 갈고 된장국에 넣어 한번 더 끓인다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00037_4.png'),(1694,337,3,'구운 애느타리버섯과 대파를 국에 넣어 끓인 후 그릇에 담는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00037_6.png'),(1695,338,1,'찬물에 표고버섯,머리와 내장을 제거한 멸치,\n다시마, 양파를 넣어 중간 불에서 10분 정도\n끓여 멸치육수를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00038_1.png'),(1696,338,2,'육수의 표고버섯 기둥, 멸치, 다시마, 양파를 건진 후 표고버섯은 편으로 썰고 청경채는 4cm 크기로 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00038_2.png'),(1697,338,3,'끓는 육수에 준비한 표고버섯과 청경채를 넣고 국간장으로 간을 한 후 마늘을 넣어 한소끔 끓인다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00038_4.png'),(1698,339,1,'올리브유, 식초, 설탕, 다진 마늘을 섞어 거품기로 충분히 저어주어 올리브마늘 드레싱을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00095_2.png'),(1699,339,2,'치커리는 싱싱하게 찬물에 담갔다가 물기를 뺀 후 한입 크기로 자르고, 적양배추, 양파, 당근은 곱게채를 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00095_3.png'),(1700,339,3,'접시에 준비한 치커리, 적양배추, 양파, 당근을 담고 올리브마늘 드레싱을 뿌린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00095_4.png'),(1701,340,1,'찬물이 담긴 냄비에 식초, 소금을 넣고 메추리알을 삶는다. 물이 끓어오르면 5분 정도 더 삶아 찬물에 헹군 후 껍질을 벗기고 반으로 자른다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00087_1.png'),(1702,340,2,'딸기를 흐르는 물에 가볍게 씻어 꼭지를 제거한 후 물기를 빼고 반으로 자른다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00087_2.png'),(1703,340,3,'양상추는 찬물에 담갔다가 물기를 빼고 한입 크기로 찢은 후 접시에 양상추, 딸기, 블루베리, 메추리알을 담고 플레인요거트를 끼얹는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00087_4.png'),(1704,341,1,'시금치는 끓는 소금물에 데쳐 찬물에 헹구어 물기를 짜고 우유를 넣고 블렌더에 곱게 갈아 체에 거른다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00089_1.png'),(1705,341,2,'껍질 벗긴 감자는 찜기에 넣어 20분 정도 삶고 꺼내서 으깨고, 아몬드는 잘게 다지며, 치커리는 곱게 다진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00089_2.png'),(1706,341,3,'으깬 감자, 다진 치커리, 시금치 우유소스, 설탕을 넣고 섞어 접시에 담고 아몬드, 크랜베리를 올리고 시금치우유 소스를 곁들인다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00089_5.png'),(1707,342,1,'곱게 다진 양파와 오이피클은 물기를 짠다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00091_1.png'),(1708,342,2,'연두부에 다진 양파, 다진 오이피클, 올리브유, 머스터드, 후추, 꿀, 식초, 레몬즙을 넣어 두부타르타르 소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00091_2.png'),(1709,342,3,'새송이버섯은 0.5cm 두께로 썰고 프라이팬에 노릇하게 구워준 후 접시에 새송이버섯과 치커리를 담고 소스를 곁들인다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00091_5.png'),(1710,343,1,'저염간장, 식초, 레몬즙, 설탕을 혼합하여 간장레몬 소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00093_1.png'),(1711,343,2,'호박, 가지, 새송이버섯은 3cm 길이로 자른 후 얇은 편으로 채 썰고, 양파, 파프리카, 피망은 호박 길이로 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00093_2.png'),(1712,343,3,'가지, 호박, 새송이버섯, 양파, 파프리카, 피망에 올리브유를 바르고 달궈진 그릴 팬에 구운 후 접시에 담고 발사믹 크레타를 뿌리고 간장레몬 소스를 곁들인다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00093_3.png'),(1713,344,1,'두유에 플레인요거트와 레몬즙, 설탕을 넣고 잘 섞어 두유요거트 소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00094_1.png'),(1714,344,2,'강낭콩은 물에 불린 후 콩과 물을 1:2.5로 넣고 20~25분 삶아 건지고 브로콜리와 컬리플라워는 한입 크기로 썰어 끓는 소금물에 살짝 데쳐 찬물에 헹궈 물기를 뺀다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00094_4.png'),(1715,344,3,'접시에 데친 브로콜리와 컬리플라워, 삶은 강낭콩, 채썬 적양파, 다진 호두, 건포도를 담고 두유요거트 소스를 곁들여 낸다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00094_5.png'),(1716,345,1,'오렌지는 깨끗이 씻어 껍질을 벗긴다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00108_1.jpg'),(1717,345,2,'당근은 깨끗이 씻어 작은 토막으로 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00108_2.jpg'),(1718,345,3,'당근, 오렌지, 물(50ml)을 믹서에 곱게 간다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00108_3.jpg'),(1719,345,4,'믹서에 갈아낸 주스는 고운 체로 거른다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00108_4.jpg'),(1720,345,5,'주스를 살얼음이 생길 만큼 시원하게 냉동한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00108_5.jpg'),(1721,345,6,'컵에 담아 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00108_6.jpg'),(1722,346,1,'잣, 아몬드, 해바라기씨, 호두, 호박씨는 다진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00111_1.png'),(1723,346,2,'끓는 물에 저염소금과 식초를 넣은 후 소면을 삶은 후 체에 건져 물기를\n뺀다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00111_2.png'),(1724,346,3,'석류는 물 600g와 함께 믹서에 갈고 체에 걸러 즙을 낸다. 그릇에 면을 담고 차갑게 식힌 석류즙을 붓고 견과류, 채 썬 오이를 고명으로 올린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00111_3.png'),(1725,347,1,'검은콩을 1시간 찬물에 담가 불린 후 삶아 익힌 후 불순물을 제거하고 흑임자, 생수, 삶은 콩, 호두를 믹서에 갈아 살엄음이 생기도록 냉동실에 넣는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00113_1.png'),(1726,347,2,'오이는 돌려 깎아 채 썰고, 토마토는 1/8크기로 썰고, 달걀은 삶아 반으로 자른다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00113_4.png'),(1727,347,3,'실곤약은 끓는 물에 데치고 찬물에 헹궈 그릇에 담은 후 콩물을 담고 오이, 토마토, 달걀을 고명으로 올려 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00113_6.png'),(1728,348,1,'브로콜리, 숙주, 표고버섯, 닭 가슴살은 다지고 다진 닭 가슴살은 소금과 후추로 밑간 한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00114_1.png'),(1729,348,2,'다진 채소와 닭가슴살, 참기름, 저염간장을 섞어 만두소를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00114_3.png'),(1730,348,3,'준비한 만두피에 만두소를 넣은 후 만두 모양으로 빚고 만두를 찜통에 넣어 찌고 그릇에 담는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00114_4.png'),(1731,349,1,'함초, 노루궁뎅이버섯, 다시마, 파, 양파, 무를 물에 넣어 10분 끓이고 향이 강한 모시조개와 냉이를 넣고 30분  끓인 후 간장으로 색을 낸다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00131_1.png'),(1732,349,2,'소면은 따로 삶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00131_4.png'),(1733,349,3,'그릇에 삶은 소면을 담은 후 육수를 붓고 지단, 슬라이스한 청고추, 실고추를 올려 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00131_5.png'),(1734,350,1,'두부에 쌀뜨물을 넣고 갈아준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00137_1.png'),(1735,350,2,'돼지고기는 썰고 김치는 물에 씻어 양념을 제거하고 3×3cm로 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00137_2.png'),(1736,350,3,'냄비에 돼지고기와 김치를 함께 볶은 후, 망에 거른 된장과 1의 두부, 고춧가루, 청양고추, 홍고추를 넣어 끓이다가 대파를 넣어 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00137_3.png'),(1737,351,1,'김치, 베이컨, 스팸, 소시지, 양파, 두부, 무는 두께 0.5cm로 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00138_1.png'),(1738,351,2,'다시마와 물을 끓여 다시마물을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00138_2.png'),(1739,351,3,'냄비에 소시지, 베이컨, 두부, 스팸, 무, 우민찌, 김치, 다시마물 300g을 넣어 끓인 후 저염된장, 양파, 대파, 다진 마늘, 떡국 떡을 넣고 재료가 다 익으면 홍고추와 청양고추를 넣어 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00138_3.png'),(1740,352,1,'감자는 믹서에 갈고 양배추는 채 썰고 고기, 당근, 청양고추, 두부는 다진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00181_4.png'),(1741,352,2,'준비해둔 재료를 모두 섞고 부침가루와 계란을 넣어 반죽한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00181_5.png'),(1742,352,3,'가열된 팬에 기름을 두르고 반죽을 부어 굽고 소스를 함께 곁들인다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00181_6.png'),(1743,353,1,'청양고추와 홍고추를 다져서 참기름에 살짝 볶은 후 볶은 고추에 마요네즈와 레몬즙을 넣어 소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00074_1.png'),(1744,353,2,'돌나물은 손질하여 찬물에 담구고 새송이버섯은 달군 프라이팬에 참기름을 두르고 노릇\n하게 굽는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00074_4.png'),(1745,353,3,'돌나물은 물기를 빼고 구운 새송이버섯과 레몬마요네즈 소스를 넣고\n버무려 접시에 담는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00074_5.png'),(1746,354,1,'배추를 소금물에 하루 동안 절인 후 물기를 빼고 석류는 즙을 낸다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00159_1.png'),(1747,354,2,'무는 채 썰고, 쪽파와 미나리는 4cm로 자른다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00159_3.png'),(1748,354,3,'무채, 미나리, 쪽파, 다진 마늘, 다진 생강, 새우젓국을 넣고 섞어 소를 만들고 절인 배추에 소를 넣고 오므려 싼다. 석류즙에 소를 채운 배추를 담가 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00159_4.png'),(1749,355,1,'발사믹 식초, 화이트와인, 다진 유자청 건더기를 넣고 졸여 소스를 만들고 대구를 손질하여 포를 뜬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00161_1.png'),(1750,355,2,'대파, 청파프리카, 홍파프리카, 황파프리카를 채 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00161_3.png'),(1751,355,3,'대구포에 밀가루를 묻혀 청파프리카, 홍파프리카, 황파프리카, 황금팽이버섯을 넣고 말아 미나리로 묶어 찐 후 소스를 뿌리고 썬 대파를 올려 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00161_4.png'),(1752,356,1,'황파프리카를 갈아 체에 내리고 멥쌀로 쌀풀을 만들어 황파프리카 즙을 섞고 물엿을 첨가하여 양념을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00162_1.png'),(1753,356,2,'배추를 소금물에 절이고 절인 배추를 찬물로 씻어 소금기를 뺀다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00162_3.png'),(1754,356,3,'소금기를 뺀 배추에 채썬 자색고구마, 무, 쪽파, 부추, 사과, 배를 놓고 양념을 부은 후 3일 동안 숙성시켜 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00162_5.png'),(1755,357,1,'양파와 마늘은 다져서 볶다가 토마토 과육과 설탕, 바질을 넣고 고추장을 섞어 토마토 소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00193_1.png'),(1756,357,2,'가지, 양송이버섯, 애호박, 사과는 썰고 살라미는 데친다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00193_2.png'),(1757,357,3,'오븐용 팬에 토마토 소스를 넓게 펴준 뒤 애호박, 가지, 양송이버섯, 살라미를 겹치게 넣고 180℃로 예열한 오븐에 넣고 30분 구워 완성한다','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00193_3.png'),(1758,358,1,'간장, 레몬즙, 설탕, 다진 홍고추를 섞어 드레싱을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00201_1.png'),(1759,358,2,'민들레 잎은 4×4cm로 썰고, 비트는 채 썰고 물에 담가 색을 뺀다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00201_2.png'),(1760,358,3,'오렌지는 씻어 껍질만 발라 채 썰고 민들레 잎, 비트, 오렌지 껍질을 섞어 접시에 담고 드레싱을 곁들인다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00201_4.png'),(1761,359,1,'올리브오일, 발사믹식초, 후춧가루를 섞어 차게 식혀 드레싱을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00202_1.png'),(1762,359,2,'가지와 토마토는 5mm두께로 썰고 120도 오븐에 20분 구운 후 구운 가지는 물기를 제거한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00202_2.png'),(1763,359,3,'팬에 올리브오일을 두르고 약불에서 채 썬 마늘을 볶다가, 가지를 넣고 구운 후 접시에 토마토, 가지를 번갈아 담고 무순으로 장식하고 드레싱을 곁들인다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00202_5.png'),(1764,360,1,'끓는 물에 배춧잎을 데친다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00636_1.png'),(1765,360,2,'당근, 호박, 표고버섯, 양파는\n입자있게 다진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00636_2.png'),(1766,360,3,'돼지고기를 썰어 불린 쌀, 다진 야채와\n함께 밥을 짓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00636_3.png'),(1767,360,4,'데친 배춧잎에 지어놓은 밥을 올려\n돌돌만다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00636_4.png'),(1768,360,5,'말아 놓은 배춧잎을 부추로 묶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00636_5.png'),(1769,360,6,'찜통에 김이 오르면 ?번을 넣고 약 5분\n정도 찐다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00636_6.png'),(1770,361,1,'대추는 돌려 깍아 씨를 제거 하고 곱게\n다진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00637_1.png'),(1771,361,2,'다진 소고기와 돼지고기에 대추와 소금\n후춧가루를 넣고 치댄다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00637_2.png'),(1772,361,3,'애호박과 단호박, 파프리카는\n입자있게 썰어 ?에 넣고 잘 치댄다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00637_3.png'),(1773,361,4,'양송이는 편으로 썰어 팬에 익히고,\n인삼을 뇌두를 자르고 깨끗이 씻어\n팬에 볶아 잘게 썰어 ?에 넣는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00637_4.png'),(1774,361,5,'재료가 골고루 섞인 떡갈비를 갈비\n모양으로 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00637_5.png'),(1775,361,6,'떡갈비를 팬에 굽고, 접시에 배춧잎을\n깔고 익힌 양송이를 올리고 떡갈비를\n담는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00637_6.png'),(1776,362,1,'닭을 깨끗이 손질하고, 부위별로\n자른다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00638_1.png'),(1777,362,2,'냄비에 가시오가피, 대파, 다시마,\n마늘, 건새우를 넣고 은근히 끓인 후\n닭을 넣고 약 20분 정도 삶아 건진 뒤\n살을 찢어둔다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00638_2.png'),(1778,362,3,'양파, 오이는 채썰고 식초, 설탕,\n소금을 넣고 초절임한다','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00638_3.png'),(1779,362,4,'겨자가루에 30℃ 정도의 물을 넣고\n골고루 섞어 발효시키고, 설탕, 식초,\n소금을 넣고 겨자소스를 만든다','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00638_4.png'),(1780,362,5,'흰곤약과 비트, 치자가루를 섞은 곤약,\n채썬 다시마를 접시에 담는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00638_5.png'),(1781,362,6,'양파, 오이 초절임과 닭살을 한쪽에\n담아 먹기 직전에 겨자소스를 올린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00638_6.png'),(1782,363,1,'찹쌀은 깨끗이 씻어 30분 정도 불린다','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00639_1.png'),(1783,363,2,'불린 찹쌀은 냄비에 넣고 질게 밥을\n한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00639_2.png'),(1784,363,3,'닭가슴살은 넓게 펴서 소금,\n후춧가루를 뿌린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00639_3.png'),(1785,363,4,'호박잎과 미나리는 끓는 물에 살짝\n데치고, 대추는 돌려 깎아 씨를\n제거하고 인삼은 뇌두를 제거한 뒤\n채를 썰어둔다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00639_4.png'),(1786,363,5,'데친 호박잎에 닭 가슴살을 올린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00639_5.png'),(1787,363,6,'닭 가슴살위에 찹쌀밥과 준비한 야채와\n대추를 올려 돌돌 말아 질게 된\n찹쌀밥에 넣고 약 20분 정도 더 쪄낸다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00639_6.png'),(1788,364,1,'된장에 두부를 넣고 골고루 섞는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00640_1.png'),(1789,364,2,'표고버섯과 마늘은 함께 갈아둔다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00640_2.png'),(1790,364,3,'미역은 충분히 불린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00640_3.png'),(1791,364,4,'냄비에 황태채와 갈아둔 표고버섯,\n마늘을 넣고 은근히 끓여 육수를\n만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00640_4.png'),(1792,364,5,'곤약은 납작납작하게 썰어 끓는 물에\n데친다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00640_5.png'),(1793,364,6,'육수에서 황태를 건져 두부된장과 함께\n갈아 육수에 붓고, 미역, 곤약,\n들깨가루를 넣고 약 20분 정도 끓인 후\n액젓으로 간을 한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00640_6.png'),(1794,365,1,'훈제오리 가슴살을 슬라이스한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00641_1.png'),(1795,365,2,'슬라이스한 훈제오리는 팬에 굽는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00641_2.png'),(1796,365,3,'양파는 채썰고 찬물에 담근 뒤 건진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00641_3.png'),(1797,365,4,'레디쉬는 채썰고 찬물에 담근 뒤\n건진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00641_4.png'),(1798,365,5,'먹기 직전에 발사믹소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00641_5.png'),(1799,365,6,'접시에 훈제오리와 양파채, 레디쉬,\n블루베리를 담고 발사믹소스를\n올린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00641_6.png'),(1800,366,1,'훈제오리 가슴살은 올리브오일,\n로즈마리, 후춧가루로\n마리네이드한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00642_1.png'),(1801,366,2,'새송이버섯은 편으로 썰고 팬에\n굽는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00642_2.png'),(1802,366,3,'오렌지는 슬라이스로 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00642_3.png'),(1803,366,4,'땅콩과 파슬리는 입자있게 다진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00642_4.png'),(1804,366,5,'마리네이드한 오리 고기를 구워 접시에\n담는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00642_5.png'),(1805,366,6,'유자청에 땅콩, 파슬리가루를 넣고\n소스를 만들고, 구워진 오리고기\n사이에 오렌지 슬라이스를 넣고\n유자청소스를 올린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00642_6.png'),(1806,367,1,'전복은 수저로 떼어내어 소금으로 비벼\n깨끗이 씻는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00643_1.png'),(1807,367,2,'시금치는 데쳐 다지고, 새우는 껍질을\n벗겨 전복, 해초와 함께 다진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00643_2.png'),(1808,367,3,'?번을 잘 섞어 전복 껍질에 넣는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00643_3.png'),(1809,367,4,'찜통에 김이 오르면 속을 채운 전복\n껍질을 넣고 약 10분 정도 찐다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00643_4.png'),(1810,367,5,'저염간장, 레몬, 설탕, 다진마늘을\n넣고 살짝 끓여 소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00643_5.png'),(1811,367,6,'간장소스에 전분을 풀어 농도를\n맞추고, 전복찜에 여러번 바르고\n식용꽃을 올린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00643_6.png'),(1812,368,1,'검은콩은 깨끗이 씻어 약 12시간 정도\n충분히 불린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00644_1.png'),(1813,368,2,'불린 검은콩은 20분 정도 삶아 깨끗이\n씻는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00644_2.png'),(1814,368,3,'삶은 검은콩은 믹서기에 곱게 갈아\n차갑게 식힌다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00644_3.png'),(1815,368,4,'오이는 씨를 제거하고 깨끗이 씻어\n채썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00644_4.png'),(1816,368,5,'물을 끓여 메밀면을 삶고, 찬물에\n여러번 헹구어 건져 물기를 뺀다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00644_5.png'),(1817,368,6,'메밀면을 그릇에 담고 차가운 콩 국물,\n땅콩, 잣, 오이, 방울토마토 및 통깨를\n올린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00644_6.png'),(1818,369,1,'어린잎은 찬물에 담근다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00645_1.png'),(1819,369,2,'마는 껍질을 벗겨 동글동글하게 썬다','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00645_2.png'),(1820,369,3,'썰어 놓은 마는 팬에 기름을 살짝\n두르고 앞뒤로 굽는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00645_3.png'),(1821,369,4,'참나물, 돈나물, 토마토, 레디쉬는\n먹기 좋은 크기로 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00645_4.png'),(1822,369,5,'겨자가루는 30℃ 물을 섞어 발효\n시킨다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00645_5.png'),(1823,369,6,'저염간장에 식초, 설탕, 발효겨자를\n넣고 골고루 섞어 소스를 만들고,\n접시에 구운 마와 손질한 야채를 넣고\n만들어 놓은 소스와 어린잎을 올린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00645_6.png'),(1824,370,1,'육수 재료를 넣고 중간 불로 끓인 뒤\n체에 걸러 육수를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00271_1.png'),(1825,370,2,'닭가슴살은 채 썬 뒤 물에 넣고\n삶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00271_2.png'),(1826,370,3,'애호박은 반달 썰고, 미나리는 5㎝\n길이로 썰고, 청양고추는 잘게 썬 뒤\n찬물에 담가 씨를 빼고, 두부는 한입\n크기로 썰어 물에 담가둔다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00271_3.png'),(1827,370,4,'김치를 한입 크기로 썬 뒤 참기름에\n볶다가 육수를 붓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00271_4.png'),(1828,370,5,'두부, 애호박, 느타리버섯, 미나리,\n닭가슴살을 넣어 끓어오르면\n달걀물과 청양고추를 넣고 조금\n더 끓여 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00271_5.png'),(1829,371,1,'대파, 마늘, 쇠고기를 물(300g)과\n함께 끓인 뒤 면포에 걸러 육수를\n만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00272_1.png'),(1830,371,2,'콩나물, 김치를 물에 씻어 손질한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00272_2.png'),(1831,371,3,'두부는 물기를 빼고, 붉은 고추는\n다진 뒤 돼지고기와 섞어 반죽해\n동그랗게 빚어 완자를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00272_3.png'),(1832,371,4,'김 오른 찜기에 완자를 넣어 찐다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00272_4.png'),(1833,371,5,'육수를 끓이고 끓어오르면 김치,\n콩나물, 새우젓을 넣는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00272_5.png'),(1834,371,6,'한소끔 더 끓이다가 완자를 넣고\n조금 더 끓여 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00272_6.png'),(1835,372,1,'풋고추는 잘게 다진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00273_1.png'),(1836,372,2,'백김치는 먹기 좋은 크기로 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00273_2.png'),(1837,372,3,'냄비에 백김치를 볶다가 김치가\n익으면 참기름, 후춧가루,\n다진 마늘을 넣고 볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00273_3.png'),(1838,372,4,'물(200g)을 넣고 끓인다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00273_4.png'),(1839,372,5,'물이 끓으면 콩비지와 간장,\n풋고추를 넣어 약한 불에서 15분\n정도 끓여 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00273_5.png'),(1840,373,1,'육수 재료를 넣고 끓인 뒤 체로 걸러\n육수를 낸다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00274_1.png'),(1841,373,2,'오징어 몸통은 큼지막하게 썰고\n다리는 얇게 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00274_2.png'),(1842,373,3,'두부와 버섯은 먹기 좋게 썰고,\n고추는 어슷하게 썰고, 고구마는\n먹기 좋은 크기로 썰고, 콩나물은\n다듬는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00274_3.png'),(1843,373,4,'김치는 먹기 좋은 크기로 썬 뒤\n냄비에 참기름을 두르고 볶다가\n고구마, 콩나물, 육수를 넣고 끓인다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00274_4.png'),(1844,373,5,'자작하게 끓으면 오징어를 넣고\n끓이고, 오징어가 익으면 들깻가루를\n넣고 끓인다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00274_5.png'),(1845,373,6,'두부, 팽이버섯, 쑥갓, 고구마,\n붉은 고추를 넣고 끓여 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00274_6.png'),(1846,374,1,'냄비에 육수 재료를 넣고 끓이다가 물이 끓어오르면 다시마를 건지고 조금 더 끓여 육수를 우려낸다.','http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306022942_1678080582607.jpg'),(1847,374,2,'주꾸미는 내장과 입, 눈을 제거하고 4cm 크기로 잘라 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306023039_1678080639676.jpg'),(1848,374,3,'김치는 국물을 꽉 짜서 한입 크기로 썰고, 무는 편 썰고, 마늘은 다지고, 대파는 어슷 썰고, 양파는 굵게 채 썰고, 두부는 납작하게 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306023103_1678080663820.jpg'),(1849,374,4,'냄비에 참기름을 두르고, 김치, 무, 양파가 투명해질 때까지 볶다가 육수를 붓고 끓으면 주꾸미, 다진 마늘을 넣어 더 끓인다.','http://www.foodsafetykorea.go.kr/uploadimg/20230313/20230313110637_1678673197807.jpg'),(1850,374,5,'김칫국물과 배즙을 2:1로 섞은 뒤 찌개에 넣어 간을 맞춘다.','http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306023149_1678080709863.jpg'),(1851,374,6,'두부, 팽이버섯을 넣고 한소끔 끓여 마무리한다','http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306023210_1678080730863.jpg'),(1852,375,1,'다시마육수재료를 물에 넣고 끓여\n육수를 낸다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00276_1.png'),(1853,375,2,'느타리버섯은 가닥가닥 떼고, 두부는\n썰고, 콩나물은 머리와 꼬리를 떼\n손질한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00276_2.png'),(1854,375,3,'배추와 미나리를 데친다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00276_3.png'),(1855,375,4,'돼지고기, 쇠고기에 고기완자양념을\n넣어 반죽한 뒤 빚어 완자를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00276_4.png'),(1856,375,5,'냄비에 모든 재료를 돌려 담은 뒤\n육수를 부어 끓인다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00276_5.png'),(1857,376,1,'통조림 햄은 한 번 데친 뒤 우유에\n담가두고, 실곤약은 식초를 넣은\n끓는 물에 살짝 데친다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00277_1.png'),(1858,376,2,'양파는 굵게 채 썰고, 느타리버섯은\n찢고, 표고버섯은 모양대로 썰고,\n팽이버섯은 끝부분을 잘라내고,\n청양고추와 붉은 고추는 어슷 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00277_2.png'),(1859,376,3,'감자, 무, 두부는 0.5㎝ 두께로 썰고,\n애호박은 반달썰기 하고 깻잎은\n채 썰어 찬물에 담가 매운맛을\n제거한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00277_3.png'),(1860,376,4,'사골육수에 다시마를 넣어 끓인 후\n한 김 식힌다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00277_4.png'),(1861,376,5,'다진 돼지고기에 다진 파, 다진 마늘,\n후춧가루, 소금을 섞어 완자를\n만들고 밀가루와 달걀물을 묻혀\n식용유(5g)를 두른 팬에 부친다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00277_5.png'),(1862,376,6,'냄비에 재료를 보기 좋게 담고\n사골육수를 부은 뒤 끓이다가\n쑥갓과 들깻가루를 넣어 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00277_6.png'),(1863,377,1,'육수 재료를 넣고 20분간 끓여\n육수를 낸다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00278_1.png'),(1864,377,2,'닭가슴살과 당근을 다져 모양을\n잡은 뒤 김 오른 찜기에 넣고 찐다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00278_2.png'),(1865,377,3,'고추, 대파는 어슷 썰고, 쑥갓,\n표고버섯, 애호박, 김치는 먹기\n좋은 크기로 썰고, 팽이버섯은\n밑동을 잘라 손질한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00278_3.png'),(1866,377,4,'당면과 숙주는 뜨거운 물에 데쳐\n준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00278_4.png'),(1867,377,5,'양념장 재료를 섞은 뒤 육수(13g)를\n넣고 양념장을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00278_5.png'),(1868,377,6,'준비한 재료를 담고 육수를 부은 뒤\n양념장을 넣고 끓여 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00278_6.png'),(1869,378,1,'통조림 햄을 썰어 끓는 물에 데친다.','http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308012641_1678249601913.jpg'),(1870,378,2,'애호박은 반달모양으로 썰고, 두부는 도톰하게 썰고, 팽이버섯은 3등분하고, 청양고추는 어슷 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308012702_1678249622285.jpg'),(1871,378,3,'김치는 씻어서 잘게 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308012717_1678249637881.jpg'),(1872,378,4,'양념장을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308012732_1678249652118.jpg'),(1873,378,5,'냄비에 물과 다시마를 넣고 살짝 끓여 육수를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308012747_1678249667092.jpg'),(1874,378,6,'육수에 손질한 재료를 담고 양념장의 1/2 분량을 넣고 중간 불에 끓이다가 쑥갓과 남은 양념장을 넣고 약한 불에 조금 더 끓여 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308012805_1678249685798.jpg'),(1875,379,1,'굴은 깨끗이 씻은 뒤 김 오른 찜기에\n찐다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00280_1.png'),(1876,379,2,'굴을 쪄낸 물(250g)에 멸치,\n표고버섯 밑동을 넣고 끓인 뒤\n멸치와 표고버섯 밑동을 건져내\n육수를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00280_2.png'),(1877,379,3,'느타리버섯은 밑동을 제거한 후\n씻어 세로로 찢고, 표고버섯은\n0.5㎝ 두께로 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00280_3.png'),(1878,379,4,'무는 나박 썰고 양파는 채 썰고,\n미나리는 3㎝ 길이로 썰고,\n대파와 고추는 송송 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00280_4.png'),(1879,379,5,'육수에 굴, 다진 마늘, 무, 양파,\n버섯을 넣고 끓인다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00280_5.png'),(1880,379,6,'들깻가루와 순두부를 넣고 한소끔\n끓인 뒤 국간장과 소금으로 간을\n맞추고 대파, 붉은 고추, 미나리를\n올려 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00280_6.png'),(1881,380,1,'냄비에 육수 재료를 넣어 끓인다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00281_1.png'),(1882,380,2,'콩을 충분히 불려 믹서기에 물을\n넣고 갈아 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00281_2.png'),(1883,380,3,'느타리버섯은 찢고, 표고버섯은 먹기\n좋은 크기로 자르고, 애호박과\n양파는 깍둑 썰고, 대파와 고추는\n송송 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00281_3.png'),(1884,380,4,'바지락은 해감해 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00281_4.png'),(1885,380,5,'육수에 콩, 느타리버섯, 표고버섯,\n애호박, 저염된장, 새우, 바지락을\n넣고 끊인다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00281_5.png'),(1886,380,6,'순두부를 넣고 끊인 후 양파, 대파,\n붉은 고추, 풋고추를 넣고 한소끔\n끓여 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00281_6.png'),(1887,381,1,'손질된 새우를 끓는 물에 데쳐 건진다.a','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00028_1.png'),(1888,381,2,'연두부, 달걀, 생크림, 설탕에 녹인 무염버터를 믹서에 넣고 간 뒤 새우(1)를 함께 섞어 그릇에 담는다.b','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00028_2.png'),(1889,381,3,'시금치를 잘게 다져 혼합물 그릇(2)에 뿌리고 찜기에 넣고 중간 불에서 10분 정도 찐다.c','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00028_3.png'),(1890,382,1,'부추는 깨끗이 씻어 물기를 제거하고, 5cm 길이로 썰고 부추에 날콩가루를 넣고 고루 섞이도록 버무린다.','http://www.foodsafetykorea.go.kr/uploadimg/20230206/20230206054820_1675673300714.jpg'),(1891,382,2,'찜기에 면보를 깔고 부추를 넣은 후 김이 오르게 쪄서 파랗게 익힌다.','http://www.foodsafetykorea.go.kr/uploadimg/20230206/20230206054834_1675673314720.jpg'),(1892,382,3,'저염간장에 다진 대파, 다진 마늘, 고춧가루, 요리당 , 참기름, 참깨를 섞어 양념장을 만들고 찐 부추는 그릇에 담아낸다.','http://www.foodsafetykorea.go.kr/uploadimg/20230206/20230206054908_1675673348152.jpg'),(1893,383,1,'물기를 빼고 2cm 정도의 크기로 썰은 부추와 양파를 양념장에 섞어 양념속을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00031_1.png'),(1894,383,2,'깨끗이 씻은 방울토마토는 꼭지를 떼고 윗부분에 칼로 십자모양으로 칼집을 낸다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00031_4.png'),(1895,383,3,'칼집을 낸 방울토마토에 양념속을 사이사이에 넣어 버무린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00031_5.png'),(1896,384,1,'사과, 순두부를 믹서에 넣고 곱게 갈아 소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00032_1.png'),(1897,384,2,'오이는 소금으로 문질러 씻어 반을 갈라 씨를 제거하고 어슷썰기를 한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00032_2.png'),(1898,384,3,'썰어 놓은 오이에 순두부사과 소스를 넣고 버무린 후 다진 땅콩을 뿌려 마무리 한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00032_3.png'),(1899,385,1,'북어채를 잘게 손으로 찢어 찬물에 헹구어 준비한 후 양파, 표고버섯, 사과는 채 썰고 새우는 등쪽의 두세 마디에 꼬챙이를 넣어 내장을 뺀 후 헹군다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00033_2.png'),(1900,385,2,'찬물에 북어채, 새우, 표고버섯, 양파를 넣고 20분 정도 끓인 후 사과를 넣어 북어의 씁쓸한 맛을 없앤다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00033_3.png'),(1901,385,3,'그릇에 담아낸다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00033_5.png'),(1902,386,1,'바나나를 반으로 잘라 반은 편 썰고\n반은 으깨고, 아보카도는 껍질과\n씨를 제거 한 후 ⅓은 편 썰고\n⅔는 으깬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00302_1.png'),(1903,386,2,'토마토는 끓는 물에 데쳐 껍질을\n제거하고 얇게 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00302_2.png'),(1904,386,3,'베이컨 2장은 채 썰고,\n1장은 구운 뒤 비슷한 크기로\n채 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00302_3.png'),(1905,386,4,'베이컨을 구운 기름에 편 썬 바나나,\n아보카도, 토마토를 넣고 바질가루를\n뿌려 굽는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00302_4.png'),(1906,386,5,'팬에 채 썬 베이컨과 다진 마늘,\n다진 양파를 볶은 후 휘핑크림,\n저염치즈를 넣고 볶다가 으깬\n아보카도, 바나나, 우유를 넣어\n농도를 맞추고 소금으로 간해\n바나나크림을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00302_5.png'),(1907,386,6,'접시에 구운 바나나, 아보카도,\n토마토를 깔고 삶은 스파게티면을\n담은 후 바나나크림을 뿌리고\n베이컨을 올려 장식해 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00302_6.png'),(1908,387,1,'신선초, 참나물, 취나물, 적겨자는\n먹기 좋은 크기로 뜯고,\n깻잎은 한입 크기로 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00303_1.png'),(1909,387,2,'양파(8g)는 채 썰고, 파스타소스에\n들어갈 양파(15g)는 굵게 다지고,\n애호박도 양파와 비슷한 크기로\n굵게 다진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00303_2.png'),(1910,387,3,'오이는 돌려 깎은 뒤 채 썰고,\n고추도 얇게 채 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00303_3.png'),(1911,387,4,'끓는 물에 쌀파스타면을 넣고 5분간\n삶아 익힌 뒤 찬물에 헹궈 물기를\n뺀다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00303_4.png'),(1912,387,5,'팬에 물(60g)을 붓고 물이 끓으면\n된장, 청국장, 다진 양파, 애호박,\n으깬 두부, 다진 마늘을 넣고\n1분 30초 정도 졸여 파스타소스를\n만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00303_5.png'),(1913,387,6,'쌀파스타면 위에 소스를 얹은 뒤\n채소를 올리고 들기름을 뿌려\n마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00303_6.png'),(1914,388,1,'감자는 한입 크기로 썰고, 양파와\n당근, 대파는 길게 채 썰고,\n청양고추는 다지고, 팽이버섯은\n깨끗이 씻어 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00304_1.png'),(1915,388,2,'달걀은 노른자와 흰자를 분리해\n지단을 부쳐 채 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00304_2.png'),(1916,388,3,'당면은 찬물에 2시간 정도 불린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00304_3.png'),(1917,388,4,'물(300g)에 멸치를 넣어 육수를\n만든 후, 황태포를 넣어 다시\n한 번 진하게 육수를 우려낸다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00304_4.png'),(1918,388,5,'육수에 감자, 당근, 양파, 당면을\n순서대로 넣고 끓인 후 불을 끄고\n팽이버섯을 얹어 잔열로 익힌다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00304_5.png'),(1919,388,6,'다진 마늘, 청양고추, 저염간장, 소금,\n후춧가루를 넣어 간을 한 뒤 지단,\n쑥갓, 대파를 얹어 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00304_6.png'),(1920,389,1,'마늘 5g은 다지고, 나머지 마늘(15g)은\n편 썰어 노릇하게 튀긴다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00305_1.png'),(1921,389,2,'깻잎은 채 썰고, 쪽파는 송송 썰고,\n파프리카는 주사위 모양으로 썰고,\n양파와 대파는 채 썰고,\n방울토마토는 반을 갈라 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00305_2.png'),(1922,389,3,'닭가슴살은 어슷하게 납작 썰어\n이태리시즈닝에 재운 뒤 팬에 구워\n준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00305_3.png'),(1923,389,4,'다진 마늘, 양파, 대파를 팬에 넣고\n향을 내다 파프리카와 방울토마토,\n양념을 넣고 볶은 뒤 한 김 식혀\n믹서에 곱게 갈아 소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00305_4.png'),(1924,389,5,'팬에 소스와 구운 닭가슴살을 넣어\n볶다가 삶은 라면을 넣고 재빠르게\n볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00305_5.png'),(1925,389,6,'튀긴 마늘과 깻잎, 쪽파를 올려\n마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00305_6.png'),(1926,390,1,'양파와 청경채, 파프라카는 채 썰고,\n쪽파는 송송 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00306_1.png'),(1927,390,2,'라면은 삶아서 체에 밭쳐 물기를\n제거한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00306_2.png'),(1928,390,3,'팬에 식용유(5g)를 두르고 다진\n마늘을 볶아 향을 낸 뒤 돼지고기를\n볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00306_3.png'),(1929,390,4,'채 썬 양파와 청경채, 파프리카를\n함께 넣고 볶다가 고추기름, 설탕,\n두반장, 라면스프로 간을 해\n볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00306_4.png'),(1930,390,5,'면을 함께 볶은 후 송송 썬 쪽파를\n뿌려 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00306_5.png'),(1931,391,1,'새우, 조개, 홍합은 손질한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00307_1.png'),(1932,391,2,'버섯은 먹기 좋은 크기로 썰고,\n양파는 채 썰고, 토마토는 씨를\n제거해 다진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00307_2.png'),(1933,391,3,'라면은 끓는 물에 데친 뒤 체에 밭쳐\n물기를 제거한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00307_3.png'),(1934,391,4,'냄비에 식용유(10g)를 두른 뒤\n새우와 조개, 홍합을 넣어 살짝 볶아\n건진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00307_4.png'),(1935,391,5,'같은 냄비에 토마토, 우유, 생크림을\n넣은 뒤 월계수잎과 정향을 넣고\n끓인다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00307_5.png'),(1936,391,6,'끓으면 데친 라면, 새송이버섯, 홍합,\n새우, 조개, 양파를 넣고 끓여 다\n익으면 파르메산 치즈가루를\n뿌린 후 그 위에 파슬리가루를 뿌려\n마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00307_6.png'),(1937,392,1,'라면을 살짝 익힌다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00308_1.png'),(1938,392,2,'배와 파인애플을 한입 크기로\n썰고, 파프리카는 깍둑 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00308_2.png'),(1939,392,3,'팬에 쇠고기 양념장과 파인애플을\n넣어 끓이다가 채 썬 쇠고기를\n넣는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00308_3.png'),(1940,392,4,'레드와인을 넣고 알코올을 날린 뒤\n매실청을 넣고 조린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00308_4.png'),(1941,392,5,'라면과 파프리카, 배를 섞은 후\n라이스페이퍼에 올려 만다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00308_5.png'),(1942,392,6,'달걀물을 묻힌 후 빵가루를 입혀\n튀긴 뒤 그릇에 어린잎채소와 함께\n담아 조린 쇠고기를 곁들여 마무리\n한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00308_6.png'),(1943,393,1,'돼지고기를 차가운 물로 헹구고\n냄비에 물(300g), 대파, 생강과 같이\n넣고 끓여 돼지고기가 익으면\n면포에 거른다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00309_1.png'),(1944,393,2,'냄비에 물(300g)을 넣어 끓으면\n가다랑어포를 넣고 1분간 끓이고\n불을 꺼 가다랑어포가 가라앉으면\n면포에 거르고, 다시 물(300g)을\n넣어 면포에 걸러낸 가다랑어포를\n넣어 약한 불로 10분간 끓인 뒤\n가다랑어포가 가라앉으면 면포에\n거른다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00309_2.png'),(1945,393,3,'돼지고기 육수와 가다랑어포 육수를\n섞은 뒤 200g을 따로 덜어\n조림양념을 넣고 끓이다가\n돼지고기를 넣고 조린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00309_3.png'),(1946,393,4,'라면은 삶아 찬물에 헹궈 건지고,\n쪽파는 송송 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00309_4.png'),(1947,393,5,'육수를 뜨겁게 끓인 뒤 그릇에\n라면사리와 함께 담고,\n돼지고기조림, 쪽파를 올리고 팬에\n남은 조림 소스를 끼얹어 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00309_5.png'),(1948,394,1,'끓는 물(600g)에 라면을 넣어\n데친다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00310_1.png'),(1949,394,2,'면은 찬물에 헹궈 물기를 뺀다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00310_2.png'),(1950,394,3,'양상추, 케일, 파프리카는 얇게 채\n썰고, 비타민은 먹기 좋은 크기로\n자른다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00310_3.png'),(1951,394,4,'유자드레싱을 고루 섞은 뒤 라면,\n채소를 버무려 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00310_4.png'),(1952,395,1,'주꾸미를 몸과 다리를 분리 후 잘 씻어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00414_01.png'),(1953,395,2,'주꾸미 다리, 미나리, 양파, 당근을 다져준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00414_02.png'),(1954,395,3,'다진 채소를 계란, 다진마늘, 생강청에 양념\n한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00414_03.png'),(1955,395,4,'양념한 3을 주꾸미 머리 속에 넣어주고\n이쑤시개로 꽂아준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00414_04.png'),(1956,395,5,'찜기에 찐다. 찔 때 레몬즙을 뿌리면 더욱\n탱탱하다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00414_05.png'),(1957,395,6,'소스를 만든 뒤 주꾸미를 함께 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00414_06.png'),(1958,396,1,'무는 모양 틀로 자른다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00415_01.png'),(1959,396,2,'무와 연근을 손질해 놓은 후 소금에 살짝\n절여준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00415_02.png'),(1960,396,3,'사과와 배는 먹기 좋게 잘라 레몬즙에 뿌려\n갈변을 막아준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00415_03.png'),(1961,396,4,'물에 청양고추를 넣어 끓여서 식힌다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00415_04.png'),(1962,396,5,'식힌 물에 국물 재료를 넣어 국물을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00415_05.png'),(1963,396,6,'만들어진 국물에 절여진 무, 연근, 사과, 배를\n넣어주어 완성한다. 24시간 이후부터 시원하게\n먹는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00415_06.png'),(1964,397,1,'다진마늘을 버터에 충분히 볶아준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00416_01.png'),(1965,397,2,'화이트와인을 뿌려주고 소스재료로 소스를\n만들어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00416_02.png'),(1966,397,3,'찜기에 살짝 져 준다. 이때 80% 정도까지만\n익혀준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00416_03.png'),(1967,397,4,'쪄준 조기는 와인과 후추로 밑간을 해준 후\n전분을 발라준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00416_04.png'),(1968,397,5,'전분를 바른 조기에 허브크러스트를 두툼하게\n올려준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00416_05.png'),(1969,397,6,'팬에 기름을 두르고 조기를 한쪽부터 구운 뒤,\n뒤집어서 다시 구워주고 소스를 뿌려 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00416_06.png'),(1970,398,1,'무, 청고추, 미나리, 대파는 먹기 좋게 썰어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00417_01.png'),(1971,398,2,'돼지머리는 냉수에 데친다. 냉수일 때부터\n돼지머리를 넣어야 물이 끓어오르면 불순물이\n제거된다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00417_02.png'),(1972,398,3,'일본 된장을 풀어 체에 걸러준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00417_03.png'),(1973,398,4,'돼지머리를 살짝 졸여준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00417_04.png'),(1974,398,5,'냄비에 국물을 끓여주다가 채소를 넣어 끓인다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00417_05.png'),(1975,398,6,'국물에 우동면을 데쳐낸 뒤 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00417_06.png'),(1976,399,1,'양파, 2가지색 파프리카, 청고추는 작은 깍두기\n모양으로 잘라준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00418_01.png'),(1977,399,2,'파인애플도 먹기 좋게 썰어준 뒤 레몬소금을\n살짝 뿌려준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00418_02.png'),(1978,399,3,'계란은 풀어서 팬에 스크램블을 만들어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00418_03.png'),(1979,399,4,'마늘을 다진 후 마늘기름으로 칵테일 새우를\n볶아준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00418_04.png'),(1980,399,5,'볶아진 칵테일새우에 잘라준 채소를 넣어\n다시 볶아준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00418_05.png'),(1981,399,6,'여기에 밥을 넣어서 볶아주고 파인애플과\n맛간장, 통깨를 넣어서 볶아준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00418_06.png'),(1982,400,1,'양파는 채 썰어 물에 담가주고, 오이는 돌려\n깎기 해서 물에 담가준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00419_01.png'),(1983,400,2,'연근은 껍질을 까고 얇게 썰어서 식초 2방울을\n넣은 물에 데쳐준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00419_02.png'),(1984,400,3,'밤도 아주 얇게 썰어서 물에 담가준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00419_03.png'),(1985,400,4,'소스 재료를 모두 넣고 믹서에 간다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00419_04.png'),(1986,400,5,'물에 데쳐낸 연근은 키친타월에 올려서 물기를\n완전히 제거한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00419_05.png'),(1987,400,6,'모든 재료를 넣고 소스에 버무려준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00419_06.png'),(1988,401,1,'코다리는 어간장, 청주, 흰후추, 생강청에\n살짝 재워준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00420_01.png'),(1989,401,2,'함초는 손질해 잘라준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00420_02.png'),(1990,401,3,'무는 소금에 살짝 절여서 수분과 염분을\n제거해준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00420_03.png'),(1991,401,4,'무와 함초를 고루 섞어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00420_04.png'),(1992,401,5,'미나리와 콩나물은 손질해준 후 찜기에 깔고\n코다리를 쪄준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00420_05.png'),(1993,401,6,'소스를 만든 뒤 채소를 깔고 코다리를 올리고\n미나리, 콩나물을 올려 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00420_06.png'),(1994,402,1,'두부는 물기를 꼭 짠 뒤 으깨어 전분, 계란과\n섞어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00421_01.png'),(1995,402,2,'우엉, 인삼, 감자는 아주 곱게 채 썰어서 냉수에\n담가준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00421_02.png'),(1996,402,3,'볶아진 모든 채소를 각각 볶아서 한데 섞어\n준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00421_03.png'),(1997,402,4,'땅콩잼으로 소스를 만들어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00421_04.png'),(1998,402,5,'김발을 깔고 비닐을 놓아 준 후 두부를 펴준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00421_05.png'),(1999,402,6,'볶아진 채소를 두부에 넣어주고 찜기에 쪄서\n식힌 뒤 한입 크기로 잘라준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00421_06.png'),(2000,403,1,'사과는 8조각으로 잘라 씨를 제거한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00422_01.png'),(2001,403,2,'청고추, 홍고추는 어슷하게 잘라준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00422_02.png'),(2002,403,3,'양파도 먹기 좋은 크기로 잘라준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00422_03.png'),(2003,403,4,'사과는 식초 물에 살짝 절여준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00422_04.png'),(2004,403,5,'양념장을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00422_05.png'),(2005,403,6,'양념장에 준비된 재료를 모두 섞어 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00422_06.png'),(2006,404,1,'주꾸미, 전복, 칵테일새우는 각각 물에 데쳐서\n준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00423_01.png'),(2007,404,2,'이때 데치고 남은 물을 국물에 이용해주고\n여기에 청주를 넣어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00423_02.png'),(2008,404,3,'양파, 청고추, 홍고추는 먹기좋게 썰어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00423_03.png'),(2009,404,4,'계란을 황백으로 부쳐서 먹기좋게 썰어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00423_04.png'),(2010,404,5,'만들어진 국물에 거피한 들깨가루와 국물재료를\n넣어 끓여서 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00423_05.png'),(2011,404,6,'준비된 재료를 냄비에 넣고 국물을 부어 끓여\n완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00423_06.png'),(2012,405,1,'참외는 껍질을 벗기고 반으로 잘라 속을\n파 준 후 먹기 좋게 잘라준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00424_01.png'),(2013,405,2,'청고추, 홍고추는 송송 잘라준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00424_02.png'),(2014,405,3,'양파와 미나리는 참외크기로 자르고, 대파는\n송송 자른다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00424_03.png'),(2015,405,4,'참외, 양파를 저염 간장에 살짝 절여준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00424_04.png'),(2016,405,5,'절여진 채소에 고춧가루로 먼저 색을 입힌다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00424_05.png'),(2017,405,6,'나머지 재료를 넣고 김치를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00424_06.png'),(2018,406,1,'연어는 얇게 모양을 살려 슬라이스 한 후\n정종에 소금을 섞어 분무기에 넣어 냉장고에\n넣어둔다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00425_01.png'),(2019,406,2,'건조된 방울토마토는 올리브오일과 후추로\n양념하여 사용한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00425_02.png'),(2020,406,3,'양상추는 먹기 좋은 크기로 뜯어 어린잎과\n함께 찬물에 담가 물기를 제거한 후 사용한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00425_03.png'),(2021,406,4,'유자청과 감식초는 함께 섞어 믹서에 갈아\n드레싱소스를 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00425_04.png'),(2022,406,5,'양파는 모양을 살려 얇게 슬라이스 하여\n찬물에 담가 물기를 제거한 뒤 사용한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00425_05.png'),(2023,406,6,'샐러드 접시에 준비된 모든 채소를 담고,\n연어는 장미 모양으로 접어서 보기좋게 담아\n드레싱 소스를 곁들여 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00425_06.png'),(2024,407,1,'콜라비는 껍질을 벗긴 후 저염간장에 30분\n정도 절여준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00426_01.png'),(2025,407,2,'우렁은 뜨거운 물에 데친 후 행군 뒤 물기를\n빼준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00426_02.png'),(2026,407,3,'미나리는 먹기 좋은 크기로 잘라준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00426_03.png'),(2027,407,4,'다진대파, 청홍고추, 양파는 송송 잘라준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00426_04.png'),(2028,407,5,'양념장에 콜라비부터 버무린 뒤 모든 재료를\n섞어서 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00426_05.png'),(2029,408,1,'코다리는 먹기 좋게 잘라서 물에 헹궈 물기를\n빼준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00427_01.png'),(2030,408,2,'감자와 무, 백일송이버섯, 미나리는 먹기 좋게\n썰어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00427_02.png'),(2031,408,3,'양파, 청양고추도 먹기 좋게 썰어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00427_03.png'),(2032,408,4,'냄비에 참기름을 넣어 코다리를 살짝 볶아준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00427_04.png'),(2033,408,5,'코다리를 볶은 냄비에 무, 감자, 국물 재료를\n넣고 충분히 끓인다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00427_05.png'),(2034,408,6,'끓고 있는 국에 양파, 청양고추, 백일송이\n버섯을 올려 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00427_06.png'),(2035,409,1,'연두부는 동글게 썰어 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00530_1.png'),(2036,409,2,'호박은 갈라 씨를 제거 하고 껍질을\n벗겨 쪄서 작은 깍둑썰기로 썰어 준비\n한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00530_2.png'),(2037,409,3,'바나나와 파프리카 토마토는 호박과\n같은 크기의 작은 깍두기로 썰어 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00530_3.png'),(2038,409,4,'닭고기살은 통후추를 넣고 약 20분 정도\n삶아 건져 작은 깍두기로 썰어 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00530_4.png'),(2039,409,5,'마와 잣, 흑임자를 갈아 놓은 뒤 생크림,\n요거트, 식초, 올리브오일, 설탕을\n섞어 샐러드 소스를 만들어 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00530_5.png'),(2040,409,6,'썰어 놓은 연두부 위에 호박 , 닭고기,\n토마토, 파프리카를 각각 올린 뒤 어린\n잎을 올리고 소스를 뿌려 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00530_6.png'),(2041,410,1,'애호박은 반달 모양으로 썰어 준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00531_1.png'),(2042,410,2,'썰어 놓은 호박에 소금을 넣고 살짝\n절여 물기를 제거하고 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00531_2.png'),(2043,410,3,'양파는 채를 썰고, 대파는 1/4로 자르고,\n홍고추는 어슷썰어 자연스럽게 씨를\n제거해 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00531_3.png'),(2044,410,4,'팬에 들기름을 넣고, 마늘을 먼저\n볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00531_4.png'),(2045,410,5,'볶아진 팬에 건새우를 넣어 볶아준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00531_5.png'),(2046,410,6,'건새우가 볶아지면, 썰어 놓은 호박을\n넣어 볶다가 양파와 대파를 넣어\n볶으면서 들깨 가루와 넣어 살짝\n볶으면서 마지막에 썰어 놓은 홍고추를\n넣어 한 번만 더 볶아 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00531_6.png'),(2047,411,1,'고구마는 찜통에 약 20분 정도 쪄서\n껍질을 벗겨 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00532_1.png'),(2048,411,2,'뜨거운 고구마가 한김 빠지면, 곱게\n으깨 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00532_2.png'),(2049,411,3,'으깨진 고구마에 바나나를 썰어\n요거트와 함께 넣는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00532_3.png'),(2050,411,4,'3번에 다시 연유를 넣어 골고루 섞는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00532_4.png'),(2051,411,5,'잣은 종이를 깔고 곱게 다져 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00532_5.png'),(2052,411,6,'어린잎은 물에 담그어, 건져 물기를\n제거해 놓고, 으깬 고구마에 다진 잣을\n넣어 샐러드를 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00532_6.png'),(2053,412,1,'새우는 껍질을 제거하고 소금과\n후춧가루를 넣어 밑간을 해놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00533_1.png'),(2054,412,2,'어린잎은 찬물에 담그어 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00533_2.png'),(2055,412,3,'튀김가루에 달걀을 넣어 잘 섞어\n튀김반죽을 만들어 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00533_3.png'),(2056,412,4,'밑간을 해 놓은 새우를 튀김반죽에\n넣어 옷을 입힌다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00533_4.png'),(2057,412,5,'누룽지는 170℃의 온도 튀김 기름에\n튀겨내고, 튀김옷 입힌 새우도 튀겨낸다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00533_5.png'),(2058,412,6,'냄비에 오렌지주스와 설탕, 식초를\n넣어 은근히 졸여 소스를 만들고,\n어린잎은 찬물에 건져 물기를 제거하고\n접시에 깔고 튀긴 누룽지와 튀긴 새우를\n올려 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00533_6.png'),(2059,413,1,'백김치는 살짝 씻어 물기를 제거하고\n잘게 썰어 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00534_1.png'),(2060,413,2,'양파와 마늘은 다지고 파는 채를 썰어\n놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00534_2.png'),(2061,413,3,'어린잎은 찬 물에 담그어 놓았다가,\n다시 소창에 건져 물기를 빼 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00534_3.png'),(2062,413,4,'냄비에 물을 넣고, 양파와 파를 넣어\n끓이다가 준비한 쭈구미를 넣고\n부드럽게 데쳐 썰어 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00534_4.png'),(2063,413,5,'식초와 간장, 설탕, 꿀, 레몬, 다진양파,\n다진마늘을 넣고 잘 섞어서 샐러드\n드레싱을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00534_5.png'),(2064,413,6,'준비한 백김치(①)와 주꾸미(②)를\n섞은 후 양상추를 접시에 깔고, 그 위에\n섞어놓은 백김치와 주꾸미를 올리고,\n홍고추와 어린잎을 위에 장식으로 올린\n후 샐러드 소스를 뿌려 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00534_6.png'),(2065,414,1,'닭고기살에 로즈마리를 뿌려 약 3시간\n이상 숙성을 시킨다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00535_1.png'),(2066,414,2,'냄비에 물을 1/3쯤 넣고, 양파채를 썰어\n넣어 끓으면, 숙성된 닭고기살을 넣고\n약 20분 정도 삶아 건진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00535_2.png'),(2067,414,3,'삶아 건진 닭고기살을 한 김 빼고, 길게\n손으로 찢어 소금과 후춧가루에 살짝\n무치고, 오이와 파프리카는 씨를 제거\n하고 채를 썰고, 당근도 오이채의 길이에\n맞게 채를 썰어 준비해 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00535_3.png'),(2068,414,4,'마늘을 다지고, 고춧가루와 설탕, 식초,\n레몬즙을 넣어 소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00535_4.png'),(2069,414,5,'뜨거운 물에 라이스페이퍼를 살짝 넣어\n바로 건진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00535_5.png'),(2070,414,6,'건져 놓은 라이스페이퍼에 준비한\n닭고기살과 파프리카, 오이, 당근 넣고\n돌돌 말아, 녹말가루를 살짝 입혀, 팬에\n굴리듯 익혀 완성하고, 준비해 놓은\n소스와 함께 제공한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00535_6.png'),(2071,415,1,'닭고기살은 천일염과 후춧가루를 뿌려\n마리네이드를 해놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00536_1.png'),(2072,415,2,'양배추와 부추는 김이 오른 찜통에\n쪄서 식혀 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00536_2.png'),(2073,415,3,'깻잎은 채를 썰고, 파프리카는 속을 제거\n하고 5cm 길이로 채를 썰고, 당근과\n양파도 같은 길이로 채를 썰어 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00536_3.png'),(2074,415,4,'마리네이드를 해 놓은 닭고기살은 팬에\n기름을 두르고, 팬이 따끈해지면 앞뒤를\n돌려가며 정종을 살살 뿌려 닭고기살을\n굽고, 닭고기살이 익으면 살을 찢어 준비\n한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00536_4.png'),(2075,415,5,'요거트와 머스터드, 꿀 ,레몬즙, 설탕을\n넣고 고루 섞어 소스를 만들어 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00536_5.png'),(2076,415,6,'쪄 놓은 양배추에 준비한 채소(③)와\n닭고기살(④)을 넣고, 돌돌 말아 쪄\n놓은 부추로 양배추를 묶어 완성하고,\n만들어 놓은 요거트 소스를 함께 제공\n한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00536_6.png'),(2077,416,1,'단호박은 1/8 등분으로 갈라 속을\n파내고 찜통에서 약 15~20분 정도\n충분히 쪄낸다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00537_1.png'),(2078,416,2,'소고기는 채를 썰어 마늘, 간장, 설탕에\n양념을 하고 팬에 볶아서 식힌다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00537_2.png'),(2079,416,3,'파프리카와 오이, 적양배추는 채를\n썰고, 무순은 물에 잠시 담그어 놓고,\n사과는 채를 썰어 설탕물에 잠시 담그어\n놓고, 팽이버섯은 밑둥만 잘라 한 줌\n집기 좋은 크기로 준비해 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00537_3.png'),(2080,416,4,'다진마늘과 다진 양파 ,올리브오일,\n설탕, 식초, 소금을 넣고, 골고루 섞어\n소스를 만들어 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00537_4.png'),(2081,416,5,'쪄 낸 단호박은 껍질을 벗기고 채에\n곱게 내려 밀가루와 물, 소금을 조금\n섞어 단호박 반죽을 만들어 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00537_5.png'),(2082,416,6,'팬에 올리브 오일을 바르고, 만들어\n놓은 단호박 반죽을 한 국자씩 떠 넣어,\n밀전병을 만들고, 밀전병이 익으면,\n한 김 식혀, 그 안에 소고기 볶음과\n채소를 넣어 돌돌 말아 소스와 함께\n완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00537_6.png'),(2083,417,1,'생선살에 생강즙과 정종을 넣고 약 30분\n정도 숙성을 시켜 비릿한 맛 제거 및 생선\n살의 탱탱함을 살려준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00538_1.png'),(2084,417,2,'콩가루와 밀가루, 카레가루, 녹말가루,\n달걀을 넣고 골고루 섞어 튀김 반죽을\n만들어 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00538_2.png'),(2085,417,3,'깻잎은 반으로 접어 채를 썰어 물에\n잠시 담그어 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00538_3.png'),(2086,417,4,'깻잎(③)은 물기를 제거하고\n튀김반죽(②)을 골고루 입힌다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00538_4.png'),(2087,417,5,'숙성시킨 생선살(①)에 녹말가루를\n살짝 입히고 튀김 반죽(②)을 골고루\n입힌 뒤, 튀김반죽을 입힌 깻잎(④)을\n얹어 튀김 기름 170℃ 온도에 넣어\n약 2분 정도 튀겨 기름을 자연스럽게\n빼 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00538_5.png'),(2088,417,6,'마요네즈와 요구르트, 설탕, 식초를\n넣어 골고루 섞어 튀김소스를 만들고,\n튀김을 접시에 담아 양상추와 함께 얹어\n완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00538_6.png'),(2089,418,1,'썰어 놓은 삼겹살에 생갑즙과 정종을\n넣고 약 2시간 정도 숙성을 시켜 준비\n한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00539_1.png'),(2090,418,2,'가지는 씨가 적은 것으로 골라 반으로\n갈라 어슷썰어 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00539_2.png'),(2091,418,3,'양파와 깻잎은 채를 썰고, 당근은\n직사각형으로 썰고, 대파는 송송 썰고,\n느타리는 손으로 찢어 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00539_3.png'),(2092,418,4,'고춧가루과 다진마늘, 간장, 올리고당,\n후춧가루, 설탕을 넣고 골고루 섞어\n양념장을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00539_4.png'),(2093,418,5,'숙성시켜 놓은 삼겹살에 만들어 놓은\n양념장을 넣고 골고루 무쳐 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00539_5.png'),(2094,418,6,'팬에 기름을 살짝 둘러 양념한 고기(⑤)\n를 먼저 볶은 후 고기가 중간쯤 익으면,\n가지(②)와 썰어 놓은 채소(③)를 넣어\n볶다가 마지막에 참기름과 잣을 넣고\n한 번 더 볶은 후 통깨를 올려 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00539_6.png'),(2095,419,1,'끓는 물에 식초 한 방울을 떨어 뜨려\n주꾸미를 데쳐 한김 식혀 먹기 좋게\n썰어놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00540_1.png'),(2096,419,2,'끓는 물에 식초 한 방울을 떨어 뜨려\n주꾸미를 데쳐 한김 식혀먹기 좋게\n썰어놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00540_2.png'),(2097,419,3,'양상추는 손으로 뜯어, 찬물에 담그어\n놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00540_3.png'),(2098,419,4,'미나리는 약 4cm 길이로 썰고, 홍고추는\n어슷 썰어 씨를 살짝 제거하고 피망은\n씨를 제거하고 미나리와 비슷한 길이로\n썰어놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00540_4.png'),(2099,419,5,'강판에 곱게 간 배즙과 무즙에 와사비,\n설탕, 다진마늘, 식초, 소금을 넣어\n샐러드소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00540_5.png'),(2100,419,6,'만들어 놓은 샐러드소스와 함께 썰어\n놓은 주꾸미(②)와 채소(③, ④)를 넣어\n먹기 직전에 버무려 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00540_6.png'),(2101,420,1,'닭가슴살에 칼을 1/3 쯤 넣고 양쪽으로\n포를 뜨고, 정종을 살짝 발라놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00541_1.png'),(2102,420,2,'포뜬 닭가슴살 위에 카레가루를 솔솔\n뿌려 숙성을 시킨다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00541_2.png'),(2103,420,3,'현미쌀은 물에 충분히 불려, 물기를\n빼 놓고, 양배추와 적 양배추는 곱게\n채를 썰어 각각 찬물에 담그어 싱싱\n해 지면 건져 물기를 빼놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00541_3.png'),(2104,420,4,'냄비에 토마토소스를 끓이다가\n생크림을 넣고 살짝 한 번 더\n끓여놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00541_4.png'),(2105,420,5,'튀김기름에 온도가 약 170℃ 정도가\n되면, 불려 놓은 현미쌀의 물기를\n제거한 뒤 튀겨 기름을 제거해 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00541_5.png'),(2106,420,6,'숙성된 닭가슴살(①)에 튀긴 현미쌀\n(⑤)을 앞뒤로 골고루 바르고 다시\n170℃ 온도의 튀김 기름에 약 3~5분\n정도 튀겨내고, 양배추와 적채를 깔고\n그 위에 튀겨진 닭가슴살을 올리고,\n토마토소스를 뿌려 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00541_6.png'),(2107,421,1,'삼겹살에 소금, 후춧가루, 생강즙,\n정종을 넣고 약 30분 정도 숙성을 시킨다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00542_1.png'),(2108,421,2,'조와 쌀은 물에 약 30분 정도 불려 밥을\n짓고, 밥이 다 익으면, 뚜껑을 열어 주걱\n으로 골고루 섞어 한 김을 빼 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00542_2.png'),(2109,421,3,'파는 길게 채를 썰어 물에 담그어 파채가\n둥글게 말리도록 한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00542_3.png'),(2110,421,4,'설탕과 식초, 레몬, 소금, 고춧가루,\n매실액을 골고루 섞어 소스를 만들어\n놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00542_4.png'),(2111,421,5,'파프리카는 속을 제거하고 양파,\n당근, 파프리카를 양파와 같은 길이로\n채를 썰고, 새송이와 표고버섯은 살짝\n데쳐 채를 썰고, 깻잎도 채를 썰어\n놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00542_5.png'),(2112,421,6,'파프리카는 속을 제거하고 양파, 당근,\n파프리카를 양파와 같은 길이로 채를\n썰고, 새송이와 표고버섯은 살짝 데쳐\n채를 썰고, 깻잎도 채를 썰어 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00542_6.png'),(2113,422,1,'미니버섯을 깨끗이 씻어 소금을 살짝\n뿌려 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00543_1.png'),(2114,422,2,'녹말가루에 물을 반쯤 넣고, 가만히\n가라앉혀 윗물은 따라 버리고, 딱딱한\n된녹말을 만들어 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00543_2.png'),(2115,422,3,'브로컬리는 끓는 물에 데쳐 작게 썰고,\n오이는 반달로 썰고, 당근은 은행잎\n모양으로 썰어 준비하고, 파프리카는\n속씨를 제거하고, 삼각지게 썰어 준비\n한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00543_3.png'),(2116,422,4,'간장과 홍초, 설탕을 넣어 골고루 섞어\n탕수육소스를 만들어 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00543_4.png'),(2117,422,5,'소금을 뿌려 놓은 미니 버섯에 만들어\n놓은 된 녹말과 달걀흰자를 넣어 골고\n루 섞는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00543_5.png'),(2118,422,6,'튀김 기름의 온도가 170~180℃가\n되면, 녹말 입힌 미니버섯을 바삭 하게\n튀겨 주고, 다시 팬에 만들어 놓은\n탕수육소스를 바글바글 끓이다가,\n썰어 놓은 채소를 넣고 살짝 익힌 후,\n물녹말을 한 숟가락 정도 넣어 끓인 후\n튀겨진 미니버섯 위에 올려 완성해 준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00543_6.png'),(2119,423,1,'연어는 소금, 후춧가루, 레몬으로\n마리네이드 한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00571_1.png'),(2120,423,2,'양파, 마늘은 입자있게 다진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00571_2.png'),(2121,423,3,'토마토는 씨를 제거하고 입자있게\n썰고, 파프리카, 피망은 채 썬 뒤\n볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00571_3.png'),(2122,423,4,'화이트크림, 생크림을 골고루 섞어\n크림소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00571_4.png'),(2123,423,5,'팬에 버터를 넣고 양파, 마늘을 볶다가\n만들어 놓은 크림소스를 넣고 졸인다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00571_5.png'),(2124,423,6,'접시에 볶은 야채를 담고, 200℃\n오븐에서 10분 정도 구운 연어를 담은\n뒤 크림소스를 올린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00571_6.png'),(2125,424,1,'쌀은 깨끗이 씻어 30분 이상 불려 밥을\n지어 식힌다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00572_1.png'),(2126,424,2,'옥수수콘은 체에 걸러 물기를 뺀다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00572_2.png'),(2127,424,3,'양파, 애호박, 당근, 양파 및\n새송이버섯은 옥수수콘 크기로 썰고\n마늘은 다진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00572_3.png'),(2128,424,4,'팬에 기름을 두르고 야채를 먼저\n볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00572_4.png'),(2129,424,5,'볶은 야채에 식혀놓은 밥을 넣고\n볶다가 저염간장, 후춧가루로 간을\n하고 옥수수콘을 넣고 살짝 볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00572_5.png'),(2130,424,6,'팬에 기름을 자작하게 넣고,\n라이스페이퍼를 둥글게 넣고 튀겨\n그릇에 담은 뒤 볶음밥을 담는다','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00572_6.png'),(2131,425,1,'연어는 끝을 뾰족하게 살려\n슬라이스한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00573_1.png'),(2132,425,2,'쌀은 깨끗이 씻어 30분 이상 불려 밥을\n지어 식힌다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00573_2.png'),(2133,425,3,'냄비에 식초, 설탕, 소금 약간과 물을\n동량으로 넣고 끓인 뒤 식혀 촛물을\n만들어 밥에 넣고 골고루 섞는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00573_3.png'),(2134,425,4,'당근과 표고버섯은 입자있게 다져 살짝\n볶아 식혀놓은 초밥에 넣고 잘\n섞어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00573_4.png'),(2135,425,5,'와사비 가루에 30℃정도의 물을 넣고\n섞은 뒤 발효 시키고, 초밥 형태를\n만들어 그 위에 와사비를 바르고\n연어를 올린 후 접시에 담는다','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00573_5.png'),(2136,425,6,'새싹과 파슬리는 찬물에 담았다 건져\n물기를 빼고, 연어 초밥 옆에 올린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00573_6.png'),(2137,426,1,'찹쌀가루는 체에 내려 2등분한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00574_1.png'),(2138,426,2,'찹쌀가루는 오미자와 치자를 우린\n뜨거운 물로 익반죽하여 비닐봉투에\n담아 숙성시킨다','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00574_2.png'),(2139,426,3,'대추는 씨를 발라내 곱게 다지고 귤병,\n유자청, 꿀을 섞어 원소병 소를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00574_3.png'),(2140,426,4,'굴병과 꿀을 섞어 원소병 소를\n준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00574_4.png'),(2141,426,5,'익반죽을 지름 3cm 크기로 동그랗게\n만들고 안에 소를 넣어 다시 동그랗게\n만든다','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00574_5.png'),(2142,426,6,'녹말가루를 입혀 끓는 물에 넣은 뒤\n떠오르면 건져 찬물에 헹궈 물기를\n빼고 그릇에 담아 꿀물을 붓고 잣을\n올린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00574_6.png'),(2143,427,1,'소고기는 넓게 펴서 소금, 후춧가루로\n밑간을 하고 굽는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00575_1.png'),(2144,427,2,'닭가슴살은 소금, 후춧가루로 밑간을\n하여 굽고 길이대로 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00575_2.png'),(2145,427,3,'미나리는 끓는 물에 넣고 데쳐 찬물에\n헹군다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00575_3.png'),(2146,427,4,'홍고추는 씨를 제거 하고 길게 썰어\n준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00575_4.png'),(2147,427,5,'달걀은 황백으로 나눠 지단을 부쳐\n길게 썰어 놓는다','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00575_5.png'),(2148,427,6,'밑간한 소고기와 닭살 에 찹쌀가루를\n뭍혀 홍고추와 달걀 황백지단을 넣어\n돌돌 말아 미나리로 띠를 둘러 팬에\n기름을 살짝 둘러 익힌다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00575_6.png'),(2149,428,1,'쌀은 깨끗이 씻어 30분 정도 불린다','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00576_1.png'),(2150,428,2,'전복은 수저로 떼어 내어 소금으로\n세척한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00576_2.png'),(2151,428,3,'준비된 전복에 버터를 두르고 굽는다','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00576_3.png'),(2152,428,4,'당근. 양파 . 양송이는 입자 있게\n다진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00576_4.png'),(2153,428,5,'냄비에 올리브 오일을 넣고 불린 쌀을\n볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00576_5.png'),(2154,428,6,'쌀이 어느 정도 볶아지면 다져 놓은\n야채를 넣어 볶다가 우유를 넣어\n끓이고, 쌀이 퍼지면 구워 놓은 전복을\n넣어 다시 끓인다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00576_6.png'),(2155,429,1,'참깨와 흑임자를 섞어 곱게 간다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00577_1.png'),(2156,429,2,'갈아 놓은 참깨와 흑임자에 설탕과\n식초를 넣고 섞는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00577_2.png'),(2157,429,3,'2번에 우유와 마요네즈를 넣고 골고루\n섞어 참깨 흑임자 드레싱을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00577_3.png'),(2158,429,4,'연두부는 동그랗게 자른다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00577_4.png'),(2159,429,5,'파프리카는 채 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00577_5.png'),(2160,429,6,'접시에 드레싱, 연두부, 파프리카,\n무순, 날치알 순으로 올린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00577_6.png'),(2161,430,1,'냄비에 마늘과 대파를 넣고 끓이다가\n닭다리를 넣고 삶는다','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00578_1.png'),(2162,430,2,'닭을 삶아 놓은 육수는 걸러 기름을\n제거 하고 차갑게 식힌다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00578_2.png'),(2163,430,3,'삶아 놓은 닭고기는 결대로 찢는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00578_3.png'),(2164,430,4,'양파, 오이와 파프리카는 채썬다','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00578_4.png'),(2165,430,5,'적채는 채를 썰어 찬물에 담궈 건져\n물기를 빼 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00578_5.png'),(2166,430,6,'차갑게 걸러 놓은 닭 육수에 발효된\n겨자와 소금 .설탕, 식초를 넣어 육수\n간을 하고, 그릇에 닭살과 오이 적채,\n파프리카 양파를 올려 차가운 육수를\n넣어 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00578_6.png'),(2167,431,1,'감자는 채를 썰어 물에 담궈 전분을\n제거하고, 양파와 당근 파는 채를 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00579_1.png'),(2168,431,2,'콩나물은 머리와 꼬리를 손질한다','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00579_2.png'),(2169,431,3,'물이 끓으면 손질한 콩나물을 넣는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00579_3.png'),(2170,431,4,'콩나물이 익으면 체에 건져 찬물에\n헹군다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00579_4.png'),(2171,431,5,'부추는 약 6cm 길이로 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00579_5.png'),(2172,431,6,'팬에 기름을 두르고 콩나물을 넣고\n살짝 볶다가 썰어 놓은 야채를 넣고\n볶으면서 소금 간을 하고 마지막에\n부추를 넣고','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00579_6.png'),(2173,432,1,'비지는 살짝 데쳐 물기를 뺀다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00580_1.png'),(2174,432,2,'무장아찌는 잘게 다져 비지에 골고루\n섞어 소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00580_2.png'),(2175,432,3,'토마토는 슬라이스로 썰어 팬에 오일을\n두르고 익힌다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00580_3.png'),(2176,432,4,'포카치아빵은 반으로 갈라 비지소스를\n바른다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00580_4.png'),(2177,432,5,'생치즈는 동그랗게 원형으로 찍어,\n비지를 바른 빵에 구운 토마토와 함께\n올리고, 다시 그 위에 비지를 올려\n접시에 담는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00580_5.png'),(2178,432,6,'루꼴라는 찬물에 담궈 건져 포카치아빵\n옆에 함께 놓는다','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00580_6.png'),(2179,433,1,'소고기는 후춧가루, 올리브오일로\n밑간을 한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00581_1.png'),(2180,433,2,'더덕은 칼로 껍질을 돌려 깎고,\n파프리카, 아스파라거스와 함께\n가늘게 채썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00581_2.png'),(2181,433,3,'파인애플, 양파, 당근, 대파는 채썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00581_3.png'),(2182,433,4,'밑간한 고기를 팬에 굽는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00581_4.png'),(2183,433,5,'따로 갈아 놓은 파인애플과 레몬즙\n꿀을 섞어 드레싱을 만는다','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00581_5.png'),(2184,433,6,'구워 놓은 고기에 더덕과 파인애플\n아스파라거스 깻잎을 넣어 돌돌 말고,\n팬에 발사믹 소스를 끓인 뒤 말아 놓은\n소고기롤을 넣어 졸인다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00581_6.png'),(2185,434,1,'새우는 껍질을 벗겨 다진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00582_1.png'),(2186,434,2,'오징어는 썰어서 다진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00582_2.png'),(2187,434,3,'양파, 샐러리, 마늘은 다져 팬에 볶아\n식힌다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00582_3.png'),(2188,434,4,'토마토는 껍질을 벗겨 다진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00582_4.png'),(2189,434,5,'다진 토마토를 팬에 볶다가 다진\n새우와 오징어, 밥을 넣어 볶고, 3번을\n넣고 볶아 동그랗게 모양을 만든다','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00582_5.png'),(2190,434,6,'동그란 밥에 레몬을 섞은 달걀노른자를\n묻히고 빵가루 옷을 입혀 팬에 기름을\n둘러 굴려가며 익힌 후 접시에 담고\n어린잎을 올린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00582_6.png'),(2191,435,1,'닭고기는 넓게 펴 소금, 후추로 밑간을\n한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00583_1.png'),(2192,435,2,'찹쌀은 깨끗이 씻어 밥을 짓는다','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00583_2.png'),(2193,435,3,'인삼은 뇌두를 제거 하고 깨끗이 씻어\n길게 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00583_3.png'),(2194,435,4,'미나리는 데쳐 찬물에 헹구고, 대추는\n씨를 제거하고 채를 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00583_4.png'),(2195,435,5,'호박잎은 끓는 물에 데쳐 찬물에\n식힌다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00583_5.png'),(2196,435,6,'데친 호박잎에 밑간한 닭고기와\n찹쌀밥을 올리고 그 위에 인삼, 데친\n미나리, 대추를 올려 돌돌 말아 찜통에\n찐 뒤 먹기 좋게 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00583_6.png'),(2197,436,1,'소고기는 홍두깨살로 준비해서\n0.3mm 두께로 썰고, 배는 껍질을 벗겨\n채 썰어 설탕을 뿌린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00584_1.png'),(2198,436,2,'끓는 물에 소금을 넣고 두릅을 데친 후\n찬물에 헹구어 건진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00584_2.png'),(2199,436,3,'소금과 설탕, 다진 마늘을 넣고 소고기\n육회 양념장을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00584_3.png'),(2200,436,4,'삶은 달걀노른자와 크림치즈, 레몬을\n섞어 짤주머니에 담는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00584_4.png'),(2201,436,5,'숙성이 잘된 아보카도는 강판에 갈아\n준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00584_5.png'),(2202,436,6,'접시에 양념한 육회와 두릅을 담고 그\n위에 배를 올리고, 달걀크림과\n아보카도를 짜서 올린다','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00584_6.png'),(2203,437,1,'닭은 깨끗이 씻고 포를 뜬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00585_1.png'),(2204,437,2,'닭고기는 15분 정도 삶아 식으면 곱게\n다져 다진 마늘, 대파, 저염간장을 넣고\n완자를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00585_2.png'),(2205,437,3,'인삼은 뇌두를 제거하고 깨끗이\n씻는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00585_3.png'),(2206,437,4,'찹쌀은 약 30분 정도 충분히 불린다','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00585_4.png'),(2207,437,5,'대추는 소금물에 깨끗이 씻고 씨를\n제거한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00585_5.png'),(2208,437,6,'믹서에 인삼과 대추, 불린 찹쌀, 물을\n정도 넣고 곱게 간 뒤, 냄비에 담아 죽을\n쑤다가 다 익으면 만들어 놓은 완자를\n넣고 한소끔 더 끓인다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00585_6.png'),(2209,438,1,'새우는 내장을 제거하고 껍질을 벗겨 깨끗이 씻는다.','http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309015216_1678337536871.jpg'),(2210,438,2,'찜기에 새우와 생강을 넣어 약 5분 정도 찐다.','http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309021346_1678338826806.jpg'),(2211,438,3,'마늘은 납작 썰고, 당근과 양파, 파, 깻잎, 청고추, 대추는 굵게 다진다.','http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309021409_1678338849298.jpg'),(2212,438,4,'숙주는 꼬리를 떼어 다듬고, 끓는 물에 살짝 데친다.','http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309021426_1678338866582.jpg'),(2213,438,5,'팬에 식용유를 두른 뒤 손질한 채소를 넣어 볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309021447_1678338887494.jpg'),(2214,438,6,'밥과 새우를 넣어 볶고, 저염간장을 넣어 볶아 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309021505_1678338905796.jpg'),(2215,439,1,'토마토는 깨끗이 씻어 슬라이스한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00587_1.png'),(2216,439,2,'두부는 원형틀을 이용해서 토마토와\n같은 크기로 만들고 소금을 살짝 뿌린\n뒤 물기를 제거한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00587_2.png'),(2217,439,3,'팬에 올리브오일을 두르고 두부를 살짝\n굽는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00587_3.png'),(2218,439,4,'어린잎은 찬물에 담근다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00587_4.png'),(2219,439,5,'발사믹소스에 설탕과 레몬즙을 넣고\n골고루 섞어 소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00587_5.png'),(2220,439,6,'두부와 준비한 토마토를 접시에 돌려\n담고 어린잎을 위에 올린 뒤 먹기\n직전에 발사믹소스와 파마산치즈를\n뿌려 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00587_6.png'),(2221,440,1,'쌀과 다시마를 넣고 쌀과 동량의\n물을 부어 밥을 고슬고슬하게\n짓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00217_1.png'),(2222,440,2,'양파는 굵게 다지고, 쪽파와 고추는\n송송 썰고, 오징어와 주꾸미는 먹기\n좋은 크기로 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00217_2.png'),(2223,440,3,'달군 팬에 들기름을 두르고 다진\n마늘을 볶아 향을 낸다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00217_3.png'),(2224,440,4,'미역을 넣고 볶다가 손질해둔\n오징어, 주꾸미, 새우살, 양파를 넣어\n볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00217_4.png'),(2225,440,5,'밥을 넣고 소금을 넣어 볶다가\n들깻가루를 넣어 볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00217_5.png'),(2226,440,6,'송송 썬 쪽파와 청양고추, 붉은\n고추를 넣어 조금 더 볶아\n마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00217_6.png'),(2227,441,1,'쌀과 현미는 물에 깨끗이 씻어 불린\n후 밥을 고슬고슬하게 짓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00218_1.png'),(2228,441,2,'감자, 고구마, 우엉, 양파, 당근,\n애호박, 연근은 작게 깍둑 썰고,\n마늘은 편 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00218_2.png'),(2229,441,3,'시금치와 참나물, 깻잎은 굵게 채\n썰고, 미나리는 2.5㎝ 길이로 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00218_3.png'),(2230,441,4,'물(50g)에 다시마를 우려내 육수를\n내고 청국장을 넣어 잘 푼 뒤\n들깻가루를 넣고 잘 저어주며 졸여\n청국장소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00218_4.png'),(2231,441,5,'팬에 올리브유와 들기름을 두르고\n양파, 마늘을 약한 불에 볶다가\n감자, 고구마, 우엉, 연근, 당근,\n애호박을 넣고 같이 볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00218_5.png'),(2232,441,6,'밥과 청국장소스를 부어 80% 정도\n볶다가 시금치, 참나물, 미나리를\n넣고 한 번 더 볶고 채 썬 깻잎을\n올려 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00218_6.png'),(2233,442,1,'쌀은 씻어서 체에 건져 1시간 이상\n불린 후 동량의 물을 부어 밥을\n짓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00219_1.png'),(2234,442,2,'아스파라거스, 새송이버섯은 작게\n깍둑 썰고, 무와 우엉, 미나리는\n다진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00219_2.png'),(2235,442,3,'식용유(10g)를 두른 팬을 중간 불로\n달궈 달걀을 넣고 스크램블로\n볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00219_3.png'),(2236,442,4,'문어, 새우살, 주꾸미는 끓는 물에\n살짝 데쳐 작게 자른다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00219_4.png'),(2237,442,5,'식용유(15g)를 두른 팬을 중간 불로\n달궈 밥을 넣어 볶다가 문어, 새우살,\n주꾸미, 스크램블 에그를 넣고 조금\n더 볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00219_5.png'),(2238,442,6,'무와 우엉에 고추장과 참기름,\n물(40g)을 넣고 묽게 졸인 후 불을\n끄고 미나리를 넣고 섞어\n미나리볶음고추장을 만들어 밥에\n곁들여 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00219_6.png'),(2239,443,1,'감자, 양파, 당근, 피망은 볶음밥에\n넣을 분량은 잘게 다지고, 카레에\n넣을 분량은 한입 크기로 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00220_1.png'),(2240,443,2,'닭가슴살도 한입 크기로 잘라\n후춧가루로 밑간한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00220_2.png'),(2241,443,3,'팬에 식용유(15g)를 두른 뒤 잘게\n다진 감자, 양파, 당근, 피망을 넣고\n볶다가 밥을 넣고 같이 볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00220_3.png'),(2242,443,4,'식용유(15g)를 두른 팬에 닭고기를\n먼저 볶다가 한입 크기로 썬 감자,\n당근, 양파, 피망, 브로콜리를 넣고\n볶은 뒤 마지막에 방울토마토를\n넣는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00220_4.png'),(2243,443,5,'토마토페이스트을 넣고 볶다가\n파프리카가루를 넣어 향을 낸다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00220_5.png'),(2244,443,6,'카레가루를 푼 물(300g)을 부어\n끓이다가 플레인 요구르트를 넣고\n농도를 맞춘 뒤 밥 위에 얹어\n마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00220_6.png'),(2245,444,1,'현미로 밥을 지은 뒤 밥 밑간을 넣고\n섞는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00221_1.png'),(2246,444,2,'톳에 톳 무침양념을 넣고 버무린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00221_2.png'),(2247,444,3,'밥에 톳을 넣고 버무린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00221_3.png'),(2248,444,4,'밥을 먹기 좋은 크기로 둥글게 뭉친\n뒤 부순 생김을 골고루 묻힌다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00221_4.png'),(2249,444,5,'주먹밥에 달걀물을 입힌 뒤 팬에\n구워 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00221_5.png'),(2250,445,1,'칵테일새우는 잘게 다진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00222_1.png'),(2251,445,2,'다진 쇠고기에 후춧가루와\n참기름(3g)으로 밑간한 후 볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00222_2.png'),(2252,445,3,'찹쌀현미밥에 참기름(4g)을 넣어\n밑간하고 식힌 후 새우와 쇠고기를\n넣어 뭉쳐준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00222_3.png'),(2253,445,4,'마늘과 고추는 볶다가 식초와\n함초가루, 설탕, 물(30g)을 넣고 졸여\n소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00222_4.png'),(2254,445,5,'밀가루는 반죽한 뒤 얇게 밀어\n삼각형으로 잘라 튀긴 후 기름을\n뺀다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00222_5.png'),(2255,445,6,'위에 주먹밥을 올리고 파인애플을\n올린 후 소스를 곁들여 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00222_6.png'),(2256,446,1,'닭봉은 손질한 뒤 후춧가루를\n섞은 우유에 담가두었다가 구워\n준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00223_1.png'),(2257,446,2,'단호박, 새송이버섯은 구워서\n준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00223_2.png'),(2258,446,3,'소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00223_3.png'),(2259,446,4,'가지, 주키니호박, 당근, 양파,\n시래기는 잘게 다진 뒤 볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00223_4.png'),(2260,446,5,'볶은 채소와 치즈를 참기름, 간장과\n함께 밥에 넣고 섞는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00223_5.png'),(2261,446,6,'구운 닭봉을 밥으로 감싼 뒤 구운\n단호박, 새송이버섯, 새싹채소와\n함께 담아 소스를 곁들여\n마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00223_6.png'),(2262,447,1,'봄동과 깻잎은 데친 뒤 체에 밭쳐\n물기를 제거한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00224_1.png'),(2263,447,2,'데친 꼬막살은 물기를 제거하고\n다져 올리브유로 양념한 밥에\n참깨와 함께 버무린 후 한입 크기로\n주먹밥을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00224_2.png'),(2264,447,3,'낙지 다리는 데쳐 찬물에 담가 식힌\n뒤 참기름(3g)에 양념하고, 두릅은\n데쳐 물기를 제거한 뒤 올리브유로\n양념한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00224_3.png'),(2265,447,4,'봄동에 꼬막밥을 넣고 만 뒤\n깻잎으로 싸고 데친 미나리로 묶어\n봄주먹밥을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00224_4.png'),(2266,447,5,'냄비에 참기름(10g)을 두르고 양파,\n당근, 애호박을 넣고 볶은 뒤 물,\n된장, 고춧가루, 다진 마늘, 붉은\n고추, 청양고추를 넣고 끓이다가\n두부를 넣고 조려 두부강된장을\n만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00224_5.png'),(2267,447,6,'봄주먹밥에 낙지와 두릅,\n두부강된장을 곁들여 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00224_6.png'),(2268,448,1,'쌀을 씻어 밥을 지은 뒤 밥 밑간을\n한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00225_1.png'),(2269,448,2,'양파, 피클, 삶은 달걀은 다진 뒤\n마요네즈에 섞어\n허브타르타르드레싱을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00225_2.png'),(2270,448,3,'김 위에 양쪽으로 밥을 펴고\n허브타르타르드레싱을 위에\n올린 후 만다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00225_3.png'),(2271,448,4,'깻잎장아찌를 바닥에 깔고 말아놓은\n롤을 올린 후 한 번 더 만다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00225_4.png'),(2272,448,5,'머스타드소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00225_5.png'),(2273,448,6,'한입 크기로 롤을 썬 뒤 새싹과\n소스를 곁들여 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00225_6.png'),(2274,449,1,'쌀을 물에 불린 뒤 완두콩을 함께\n넣고 밥을 짓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00226_1.png'),(2275,449,2,'달걀을 풀어 체에 내린 뒤 지단을\n부치면서 반 정도 익었을 때 그 위에\n얇게 썬 주키니호박, 당근, 가지를\n올려 익힌다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00226_2.png'),(2276,449,3,'참치를 참치밑간에 재운 뒤 겉만\n살짝 익힌다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00226_3.png'),(2277,449,4,'김에 밥을 올리고, 뒤집어 참치를\n올려 만 뒤 그 위에 지단을 올려\n한 번 더 만다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00226_4.png'),(2278,449,5,'사과드레싱을 만들고,\n토마토소스 재료를 간 뒤 체에\n거른다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00226_5.png'),(2279,449,6,'참치비빔밥롤을 담은 뒤\n토마토소스를 곁들이고, 케일에\n사과드레싱을 뿌려 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00226_6.png'),(2280,450,1,'소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00227_1.png'),(2281,450,2,'파프리카와 파인애플을 먹기 좋게\n썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00227_2.png'),(2282,450,3,'스크램블 에그를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00227_3.png'),(2283,450,4,'김발 위에 ⅔크기로 자른 김을 놓고\n밥을 고루 편 뒤 새싹채소,\n스크램블 에그, 파프리카, 기름 뺀\n참치, 파인애플을 올리고 소스를\n고르게 뿌린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00227_4.png'),(2284,450,5,'반으로 접어 먹기 좋게 썰어\n마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00227_5.png'),(2285,451,1,'당근, 피망, 양파를 잘게 다진 뒤\n기름에 살짝 볶아 밥에\n마요네즈(10g)와 함께 넣어 섞는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00228_1.png'),(2286,451,2,'통조림 연어는 기름기를 빼고,\n식초를 넣은 끓는 물에서 30초 정도\n데친다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00228_2.png'),(2287,451,3,'데리야키소스와 마요네즈(10g)에\n연어를 넣고 버무려 양념한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00228_3.png'),(2288,451,4,'밥을 동그랗게 빚은 뒤 가운데에\n연어를 넣고 주먹밥을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00228_4.png'),(2289,451,5,'달걀물과 빵가루를 입혀 160℃로\n예열한 기름에 바삭하게 튀긴다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00228_5.png'),(2290,451,6,'연어주먹밥튀김을 담고\n어린잎채소를 곁들인 뒤\n오리엔탈소스를 곁들여 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00228_6.png'),(2291,452,1,'오징어 몸통 안쪽에 칼집을 내고\n끓는 물에 데친다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00229_1.png'),(2292,452,2,'파프리카와 당근, 피망은 작게 다져\n볶은 뒤 밥에 넣어 섞는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00229_2.png'),(2293,452,3,'쇠고기는 참기름에 볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00229_3.png'),(2294,452,4,'달걀을 풀어 약한 불로 달군 팬에\n부은 뒤 김가루를 뿌려 지단을\n부치고, 바닥이 익으면 깻잎과\n밥을 올린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00229_4.png'),(2295,452,5,'데친 오징어, 볶은 쇠고기 순으로\n올려 만 뒤 랩으로 싼다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00229_5.png'),(2296,452,6,'고추장과 매실청을 섞은 뒤 팬에\n넣고 약한 불에서 끓여 소스를\n만들고 한입 크기로 썬 김밥에\n구운 버섯을 함께 곁들여\n마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00229_6.png'),(2297,453,1,'닭고기 삶는 재료를 물(100g)에 넣어\n끓이다가 닭가슴살을 넣고 삶아\n한입 크기로 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00230_1.png'),(2298,453,2,'양배추는 곱게 채 썰고, 청포묵은\n먹기 좋은 크기로 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00230_2.png'),(2299,453,3,'숙주는 끓는 물에 데쳐 물기를 뺀다','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00230_3.png'),(2300,453,4,'비빔소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00230_4.png'),(2301,453,5,'쌀에 물을 붓고 밥을 짓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00230_5.png'),(2302,453,6,'밥 위에 닭가슴살, 양배추, 청포묵,\n숙주, 달걀지단, 무순을 담아\n마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00230_6.png'),(2303,454,1,'조미된 족발은 뜨거운 맥주에 데쳐내 기름기를\n제거한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00325_01.png'),(2304,454,2,'고구마는 편으로 썰어 냉수에 헹궈 기름\n없는 팬에 구워준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00325_02.png'),(2305,454,3,'가지는 편으로 썰어서 수분을 제거한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00325_03.png'),(2306,454,4,'가지는 편으로 썰어 살짝 구워준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00325_04.png'),(2307,454,5,'백김치는 물에 헹궈서 손으로 꼭 짠 후 송송\n썰어서 양념을 해 무쳐준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00325_05.png'),(2308,454,6,'무쳐준 김치와 함께 구워진 채소와 족발수육을\n담아 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00325_1.png'),(2309,455,1,'함초는 송송 다져준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00326_01.png'),(2310,455,2,'당근, 새송이, 샐러리, 양파를 송송 다져준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00326_02.png'),(2311,455,3,'볼에 소고기, 돼지고기, 다져 놓은 채소와\n다진마늘, 다진대파, 참기름을 넣고 반죽해준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00326_03.png'),(2312,455,4,'여기에 함초 다진 것을 넣고 다시 반죽해 준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00326_04.png'),(2313,455,5,'떡갈비 모양으로 만들어준 후 팬에 노릇하게\n구워준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00326_05.png'),(2314,455,6,'소스를 만들어 구워진 떡갈비를 졸여준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00326_06.png'),(2315,456,1,'모시조개는 볶은소금을 넣어서 해감시킨다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00327_01.png'),(2316,456,2,'준비된 다시마물에 준비된 채소의 국물재료를\n넣고 국물을 만들어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00327_02.png'),(2317,456,3,'만들어진 국물에 모시조개를 넣고 청주를\n부어서 국물을 만들어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00327_03.png'),(2318,456,4,'쪽파는 송송 다지고 마늘은 곱게 다져주고\n청홍고추는 가늘게 채 썰어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00327_04.png'),(2319,456,5,'면을 각각 삶아준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00327_05.png'),(2320,456,6,'삼색 면을 그릇에 담고 만들어진 국물을\n부워서 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00327_06.png'),(2321,457,1,'당근, 청경채, 배추, 애호박, 팽이버섯은 먹기\n좋은 크기로 잘라준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00328_01.png'),(2322,457,2,'흑돼지고기, 저염된장, 후추를 넣어서 불순물을\n제거하면서 고기를 삶아준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00328_02.png'),(2323,457,3,'천연다시다로 육수를 만들어 체에 걸러준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00328_03.png'),(2324,457,4,'손질한 야채들과 청양고추를 잘라 함께 육수에\n데쳐 국물에 매운 맛을 낸다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00328_04.png'),(2325,457,5,'곁들이장을 만들어 준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00328_05.png'),(2326,457,6,'냄비에 데쳐준 채소와 국물을 붓고 고기를\n먹기좋게 썰어 소스랑 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00328_06.png'),(2327,458,1,'바지락은 해감을 시켜준 후 물에 넣어 바지락\n육수를 만들어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00329_01.png'),(2328,458,2,'바지락살은 따로 떼어내어 다진소고기와\n다시 다져서 양념해 볶아준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00329_02.png'),(2329,458,3,'두부는 물기제거를 한 후 함초, 깻잎, 다진양파,\n를 넣어 치대어 두부볶음을 만들어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00329_03.png'),(2330,458,4,'애호박은 채 썰어주고 양파, 오이, 당근, 표고도\n채 썰어 각각 볶아준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00329_04.png'),(2331,458,5,'볶은 바지락과 쌀을 넣어 밥을 한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00329_05.png'),(2332,458,6,'몰드에 밥과 각종 채소들을 올려주고 마지막에\n두부 스크램블을 올려 밥을 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00329_06.png'),(2333,459,1,'뜨거운 물에 파스타면을 삶아낸 뒤 물기를\n빼준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00330_01.png'),(2334,459,2,'송송 썬 청양고추를 생들기름에 볶아주다\n면을 볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00330_02.png'),(2335,459,3,'볶아준 청양고추에 삶아진 면을 볶아준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00330_03.png'),(2336,459,4,'열무김치는 송송 썰어서 들기름에 살짝\n볶아준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00330_04.png'),(2337,459,5,'오이는 돌려깎기 해서 채 썰어주고 청고추,\n2가지색 파프리카, 당근도 채 썰어 각각 볶아\n준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00330_05.png'),(2338,459,6,'청양고추에 볶아진 파스타면을 볶은 채소와\n한 번 더 볶아 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00330_06.png'),(2339,460,1,'갈비는 핏물을 빼주고 뜨거운 물에 80% 이상\n데쳐준 뒤 갈비와 감자를 물을 자작하게 넣고\n청주, 생강청을 넣고 푹 삶아준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00331_01.png'),(2340,460,2,'양파, 청고추, 홍고추는 먹기 좋게 썰어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00331_02.png'),(2341,460,3,'마른미역줄기는 냉수에 행군 뒤 물기를 빼준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00331_03.png'),(2342,460,4,'양념장을 바글바글 끓여준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00331_04.png'),(2343,460,5,'끓고 있는 양념장에 삶아진 갈비, 감자, 당근\n순으로 끓이다 메추리알을 넣고 졸여준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00331_05.png'),(2344,460,6,'마지막에 미역줄기를 넣고 볶아주는 형식으로\n갈비찜을 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00331_06.png'),(2345,461,1,'곤드레는 뜨거운 물에 데쳐낸 뒤 깨끗하게\n헹구고 송송 썰어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00332_01.png'),(2346,461,2,'두부의 물기를 짜 준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00332_02.png'),(2347,461,3,'양념장 재료와 물기를 짠 두부로 양념장을\n만들어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00332_03.png'),(2348,461,4,'느타리버섯은 뜨거운 물에 데쳐낸 후 수분을\n빼 가늘게 찢어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00332_04.png'),(2349,461,5,'냄비에 참기름을 두르고 곤드레를 볶다가 쌀을\n넣고 밥을 해준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00332_05.png'),(2350,461,6,'뜸을 들일 때 느타리버섯을 올려주어 밥을\n완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00332_06.png'),(2351,462,1,'찹쌀은 불려주고 전복은 손질해 내장과 분리해\n준 뒤 청주를 넣어서 전복 내장을 믹서에\n갈아준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00333_01.png'),(2352,462,2,'전복 몸에 칼집을 내준 후 참기름을 두른 팬에\n구워준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00333_02.png'),(2353,462,3,'당근과 미역은 송송 잘라준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00333_03.png'),(2354,462,4,'전복내장을 먼저 참기름에 충분히 볶아준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00333_04.png'),(2355,462,5,'내장을 볶아주다가 불린 찹쌀을 넣고 충분히\n볶아준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00333_05.png'),(2356,462,6,'죽이 완성될 때 당근, 미역을 넣고 죽을 끓여\n주고 전복은 고명으로 올려준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00333_06.png'),(2357,463,1,'주꾸미는 세척해 물기를 빼준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00334_01.png'),(2358,463,2,'무와 단호박은 먹기 좋게 썰어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00334_02.png'),(2359,463,3,'청고추, 미나리, 양파를 먹기 좋게 썰어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00334_03.png'),(2360,463,4,'청양 고추를 어슷하게 썰고 마늘은 편으로 썰어\n국물을 끓여준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00334_04.png'),(2361,463,5,'국물이 만들어지면 무, 단호박을 넣고 끓여준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00334_05.png'),(2362,463,6,'국물에 대파를 넣어주고 모든 재료를 넣어\n완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00334_06.png'),(2363,464,1,'파프라카, 양파, 홍고추는 가늘게 채 썰어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00335_01.png'),(2364,464,2,'함초는 세척 후 먹기 좋게 손질해 준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00335_02.png'),(2365,464,3,'무순을 물 속에 담가준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00335_03.png'),(2366,464,4,'편으로 썰어준 소고기에 채 썰어준 채소와\n함초를 꼭 싸 말아준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00335_04.png'),(2367,464,5,'마늘은 편으 로 썰 어 마늘기름에 한 번\n구워준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00335_05.png'),(2368,464,6,'구운 마늘을 깔고 말아준 고기를 굽는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00335_06.png'),(2369,465,1,'닭가슴살을 이용해 국물을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00336_01.png'),(2370,465,2,'닭가슴살은 먹기 좋게 찢어 흰 후추, 버섯마늘\n소금으로 밑간을 해준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00336_02.png'),(2371,465,3,'콩나물은 머리를 떼어내고 데쳐준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00336_03.png'),(2372,465,4,'계란은 황백지단으로 부친 후 채 썰어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00336_04.png'),(2373,465,5,'3종류의 묵은 먹기 좋은 크기로 썰어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00336_05.png'),(2374,465,6,'그릇에 밥을 담고 콩나물을 올리고 3종류의\n묵을 올린 후 계란으로 고명해 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00336_06.png'),(2375,466,1,'쌀을 깨끗하게 씻은 후에 쌀뜨물은 따로\n보관하고 불려준 쌀로 밥을 해주고 접시에\n펼쳐 식혀준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00337_01.png'),(2376,466,2,'우엉과 연근, 감자는 송송 다져준 후 아린 맛을\n빼기위해 물에 담가준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00337_02.png'),(2377,466,3,'우엉과 연근, 감자는 물기를 빼고 볶아준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00337_03.png'),(2378,466,4,'청고추, 양파, 당근은 송송 다져서 함께\n볶아준 뒤, 함초 소금을 이용해 1차 간을\n해준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00337_04.png'),(2379,466,5,'그 릇 에 모 든 재 료 를 넣 고 오 니 기 리 를\n만들어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00337_05.png'),(2380,466,6,'그릇에 담아 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00337_06.png'),(2381,467,1,'단 호박은 속을 파 준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00338_01.png'),(2382,467,2,'찹쌀은 물에 불려준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00338_02.png'),(2383,467,3,'밤은 먹기 좋게 잘라서 물에 담가준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00338_03.png'),(2384,467,4,'대추는 씨를 제거하고 먹기 좋게 잘라준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00338_04.png'),(2385,467,5,'양념장을 만들어 먼저 쌀과 밤을 재워준 후\n찰밥을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00338_05.png'),(2386,467,6,'단호박 속에 찰밥을 넣어서 찜기에 쪄준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00338_06.png'),(2387,468,1,'망고는 손질 후 버터로 살짝 볶고 레드와인을\n넣고 졸이다가 믹서로 갈아주고 딸기잼으로\n간과 농도를 맞추어 레드와인 소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00339_01.png'),(2388,468,2,'소 채끝살은 손질 후 만들어진 레드와인 소스에\n마리네이드 해준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00339_02.png'),(2389,468,3,'감자는 껍질을 제거 후 먹기 좋은 크기로 잘라서\n뜨거운 물에 데쳐내 버터에 볶아준다. 당근은\n먹기좋은 크기로 잘라 뜨거운 물에 데쳐 버터\n에 볶아주고, 시금치도 데친 후 수분을 제거하\n고 버터에 볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00339_03.png'),(2390,468,4,'마리네이드 한 고기를 구워준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00339_04.png'),(2391,468,5,'마리네이드 하고 남은 망고소스를 다시 팬에\n졸여 소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00339_05.png'),(2392,468,6,'접시에 준비된 채소와 안심을 담고 소스를\n뿌려 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00339_06.png'),(2393,469,1,'식빵은 가장 자리를 잘라 밀대를 이용\n하여 얇게 밀어 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00441_1.png'),(2394,469,2,'감자는 삶은 뒤 곱게 으깨어 올리고당을\n넣고 골고루 섞는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00441_2.png'),(2395,469,3,'달걀은 약 13분 정도 삶아 껍질을\n벗기고, 반으로 갈라 썰어놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00441_3.png'),(2396,469,4,'당근과 양파 오이도 얇게 썰어놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00441_4.png'),(2397,469,5,'토마토는 포를 떠서 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00441_5.png'),(2398,469,6,'으깬 감자(②)에 준비한 달걀(③)과\n채소(④)를 넣고 소금을 약간 넣은 뒤\n골고루 섞어, 밀어 놓은 식빵에 토마토,\n치즈, 양상추와 함께 넣어 돌돌 말아\n완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00441_6.png'),(2399,470,1,'황태는 가위로 약 3cm 길이로 잘라\n스프레이로 물기를 준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00442_1.png'),(2400,470,2,'밀가루를 세 군데로 나눠 각각 찹쌀\n가루와 녹말가루, 삼색 가루를 넣어\n세 가지의 색을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00442_2.png'),(2401,470,3,'만들어 놓은 밀가루에 달걀을 넣어\n골고루 섞는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00442_3.png'),(2402,470,4,'튀김 반죽(③)에 황태(①)를 넣어\n섞은 후, 튀김 기름 170℃ 의 온도에서\n약 1분 정도 튀겨 기름을 빼 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00442_4.png'),(2403,470,5,'파프리카는 속씨를 제거하고, 양파와\n당근, 오이, 파인애플과 함께 썰어 준비\n한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00442_5.png'),(2404,470,6,'저염간장에 설탕과 식초를 넣어 골고루\n섞은 후 냄비에서 바글바글 끓이다가\n물녹말을 넣고, 썰어놓은 채소를 넣어\n한 번 더 끓인 후 황태 탕수육(④)에\n곁들여 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00442_6.png'),(2405,471,1,'소시지는 먹기 좋은 크기로 썰어 나무\n막대기에 꽂아놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00443_1.png'),(2406,471,2,'파프리카는 작게 다져 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00443_2.png'),(2407,471,3,'으깬 감자를 준비된 밥과 함께 골고루\n섞는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00443_3.png'),(2408,471,4,'으깬 감자를 다시 준비된 밥과 함께\n소금을 조금 넣고 골고루 섞는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00443_4.png'),(2409,471,5,'밥과 감자가 잘 섞어지면, 다시 다져진\n파프리카를 넣고 섞어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00443_5.png'),(2410,471,6,'막대기에 밀가루를 살짝 바르고, 소시\n지에 반죽(⑤)을 감싸듯 손으로 둥글게\n말아 밀가루와, 달걀물, 빵가루 순서로\n입혀 튀김 기름 170℃의 온도에서\n약 2분 정도 튀긴 후 기름을 제거하여\n완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00443_6.png'),(2411,472,1,'소등심은 소금과 후춧가루, 로즈마리를\n뿌려 약 30분 이상 숙성을 시킨다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00444_1.png'),(2412,472,2,'애호박은 동그랗게 자르고, 양파는 형태\n그대로 떼어내고, 가지는 직사각형으로\n잘라 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00444_2.png'),(2413,472,3,'파프리카는 속을 파내고 작은 사각으로\n자르고, 토마토는 씨를 제거하고\n네모지게 잘라 준비해 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00444_3.png'),(2414,472,4,'사과는 껍질을 깨끗이 씻어 길쭉하게\n썰어놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00444_4.png'),(2415,472,5,'발사믹소스에 설탕과 마늘을 넣고 썰어\n놓은 사과채를 넣어 잘 섞은 후 바글바글\n끓여 소스를 만들어놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00444_5.png'),(2416,472,6,'팬이 따끈해지면, 호박과 양파, 가지를\n구워 내고, 팬에 소등심을 앞뒤로 구워\n먹기 좋은 크기로 자른 뒤 구워 놓은\n양파와 호박, 가지에 각각 올리고,\n끓여놓은 소스와 파프리카, 토마토를\n얹어 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00444_6.png'),(2417,473,1,'당근은 채를 곱게 썰어 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00445_1.png'),(2418,473,2,'달걀은 노란자와 흰자로 나눠 각각\n지단을 부쳐 약 5cm 길이로 채를\n썰어놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00445_2.png'),(2419,473,3,'시금치는 끓는 물에 소금을 넣고 파랗게\n데쳐 물기를 제거하고 무쳐놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00445_3.png'),(2420,473,4,'돼지고기는 마늘, 파, 설탕, 맛술, 간장,\n후춧가루, 통깨, 참기름을 넣고 30분간\n숙성시킨 뒤 팬에 볶아서 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00445_4.png'),(2421,473,5,'고구마는 삶아 으깨고, 두부는 소창에\n물기를 짜고, 토마토와 양파, 견과류는\n입자있게 다져섞는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00445_5.png'),(2422,473,6,'라이스 페이퍼를 따뜻한 물에 담궜\n다가 바로 꺼내어 으깬 고구마(⑤)를\n먼저 깔고, 그 위에 준비한 재료(②,\n③, ④)를 올려 돌돌 말은 뒤 먹기 좋은\n크기로 썰어 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00445_6.png'),(2423,474,1,'밀가루를 세 개로 나눠 호박가루와\n백년초가루, 시금치가루를 각각 넣고\n물, 식용유, 소금을 넣어 반죽 한 후\n비닐봉지에 담아 1~2시간 정도 숙성\n시킨다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00446_1.png'),(2424,474,2,'양파, 마늘, 버섯들은 입자있게 다져\n준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00446_2.png'),(2425,474,3,'두부는 소창을 이용하여 물기를 짜낸다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00446_3.png'),(2426,474,4,'새우는 껍질과 내장을 제거하고 다져,\n마늘을 넣고 골고루 섞어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00446_4.png'),(2427,474,5,'다진 채소(②), 으깬 두부(③), 새우\n(④)를 넣고 섞어서 만두소를 만들어\n준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00446_5.png'),(2428,474,6,'숙성된 만두 반죽(①)을 얇게 밀어\n꽃 모양으로 찍어 만두소(⑤)를 넣은\n뒤, 반죽을 맞잡아 모양을 만든다.\n우유와 생크림을 끓인 뒤 만들어 놓은\n만두를 넣고 은근히 찜을 하듯이 익혀\n완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00446_6.png'),(2429,475,1,'소고기와 돼지고기에 찹쌀가루와 밥을\n넣고 골고루 섞는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00447_1.png'),(2430,475,2,'섞여진 고기(1)에 파와 후춧가루, 간장,\n맛술, 생크림을 넣고 다시 잘 섞어 30분\n이상 숙성을 시킨다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00447_2.png'),(2431,475,3,'새송이버섯은 다지고, 시금치는 뜨거운\n물에 데쳐 물기를 제거하고 잘게 다지고,\n당근도 다져 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00447_3.png'),(2432,475,4,'양파와 마늘은 다져서 볶아 준비해\n놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00447_4.png'),(2433,475,5,'떡볶이 떡은 뜨거운 물에 잠시 담그어\n부드러워지면 꺼내서 잘게 다진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00447_5.png'),(2434,475,6,'숙성된 고기(②)에 다진 채소(③)와 볶은\n마늘과 양파(④), 떡볶이떡(⑤)을 넣고\n섞이도록 치댄 후 작은 떡갈비 모양을\n만들어 팬에 기름을 두르고, 앞뒤를 돌려\n가며 익힌 후, 냄비에 간장과 올리고당을\n넣고 끓이다가, 익힌 떡갈비를 넣고 자작\n하게 졸여 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00447_6.png'),(2435,476,1,'쌀은 깨끗이 씻어 약 30분 이상 불려\n물기를 빼고 절구에 빻아놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00448_1.png'),(2436,476,2,'냄비에 물을 넣고, 다시마와 건새우 반을\n넣고 끓여 간단한 육수를 만들어 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00448_2.png'),(2437,476,3,'건새우 반은 다져서 따로 준비하고,\n양파와 당근은 입자있게 다지고, 버섯을\n편으로 썰어 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00448_3.png'),(2438,476,4,'홍합은 끓는 물에 소금을 넣고 데쳐\n껍질을 제거해 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00448_4.png'),(2439,476,5,'냄비에 참기름을 넣고 빻아 놓은 쌀을\n넣어 은근히 볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00448_5.png'),(2440,476,6,'볶은 쌀(⑤)에 육수(②)를 붓고\n끓이다가 양파, 당근, 버섯(③)과\n홍합(④)을 넣고 어우러지게 나무\n주걱으로 저어가면 끓이다가 죽이\n다 익을 때쯤 다져 놓은 건새우\n(③)를 넣고 한 번 더 끓인 후 완성\n한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00448_6.png'),(2441,477,1,'우유에 등심을 넣어 30분간 재워 놓은\n뒤, 후춧가루, 정종을 발라 1시간 이상\n숙성시킨다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00449_1.png'),(2442,477,2,'방울토마토는 반으로 잘라 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00449_2.png'),(2443,477,3,'양상추는 먹기 좋은 크기로 찢어 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00449_3.png'),(2444,477,4,'피클은 입자 있게 다져 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00449_4.png'),(2445,477,5,'숙성시킨 등심(①)은 물기를 제거하고,\n먹기 좋은 크기로 썰어 밀가루, 달걀물,\n빵가루 순으로 입혀, 튀김 기름\n170~180℃ 온도에 약 3분 정도 튀긴\n후 기름을 빼 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00449_5.png'),(2446,477,6,'삶은 달걀은 다지고 피클(④)에\n마요네즈를 넣어 섞어 샐러드 소스를\n만들고, 접시에 양상추를 깔고 그 위에\n어린잎채소, 돈가스(⑤)와 방울토마토\n(②)를 올려 소스와 함께 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00449_6.png'),(2447,478,1,'스파게티는 끓는 물에 소금을 넣고 약\n10분 정도 삶아 건져 올리브 오일에\n살짝 발라 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00450_1.png'),(2448,478,2,'양송이는 껍질을 벗겨 편으로 썰어\n놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00450_2.png'),(2449,478,3,'마늘과 양파는 굵게 다져놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00450_3.png'),(2450,478,4,'조개는 끓는 물에 데쳐 해감을 씻고,\n삶은 물을 소창에 걸러 육수를 만들어\n놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00450_4.png'),(2451,478,5,'냄비에 버터를 넣고, 다진 마늘과\n양파를 넣어 볶다가 밀가루를 넣고\n은근히 볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00450_5.png'),(2452,478,6,'볶고 있는 채소(⑤)에 육수(④)를 부어\n한소끔 끓인 뒤, 우유와 생크림을 넣고\n다시 끓으면 새우와 삶은 조개를 넣고\n살짝 끓인 후, 삶아놓은 스파게티면\n(①)을 넣고 한 번 더 끓이고 그 위에\n파슬리 가루를 살짝 뿌려 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00450_6.png'),(2453,479,1,'닭날개는 끝을 잘라 뒤로 뒤집어 봉을\n만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00451_1.png'),(2454,479,2,'오렌지즙과 레몬즙을 짜서 섞어 주고,\n생강을 갈아 소창에 걸러 즙을 낸다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00451_2.png'),(2455,479,3,'닭봉(①)에 생강즙, 오렌지 ․ 레몬즙\n(②)을 발라 숙성시킨 후 다시 카레\n가루를 입힌다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00451_3.png'),(2456,479,4,'땅콩은 물기 없이 입자있게 다진다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00451_4.png'),(2457,479,5,'양파를 입자있게 다져 다진 땅콩과\n마요네즈, 파슬리가루, 요거트를\n넣고 골고루 섞어 소스를 만들어\n놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00451_5.png'),(2458,479,6,'카레가루를 입힌 닭봉은 튀김기름\n170~180℃ 온도에서 약 3분 정도 튀겨\n기름을 빼고, 접시에 어린잎을 담고\n만들어 놓은 소스와 닭봉을 함께 제공\n하여 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00451_6.png'),(2459,480,1,'보리는 깨끗이 씻어 물에 약 30분 이상\n불려 놓고, 당근, 양파, 마늘, 대파는\n입자있게 다져 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00452_1.png'),(2460,480,2,'시금치는 끓는 물에 소금을 넣고 데친 후\n생크림을 넣고 함께 갈아서 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00452_2.png'),(2461,480,3,'오징어는 껍질을 벗겨 안쪽에 칼집을\n내어 새우와 함께 데치고, 조개는 해감\n후 다시마를 넣고 삶은 뒤 소창에 걸러\n육수를 만들어 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00452_3.png'),(2462,480,4,'냄비에 버터를 넣고, 다진 마늘과 양파\n당근을 볶다가 불린 보리를 넣어 다시\n볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00452_4.png'),(2463,480,5,'볶아지는 냄비에 조개 삶은 육수를\n넣어 끓인다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00452_5.png'),(2464,480,6,'끓여지는 냄비에 데친 조개와 해물,\n치즈, 우유를 넣어 어우러지게 저어\n가며 졸이듯 끓이다가 마지막에\n시금치와 생크림 갈은 것(②)을\n넣고 살짝 끓인 후 파슬리 가루를\n살짝 뿌려 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00452_6.png'),(2465,481,1,'소고기와 돼지고기를 섞어, 후춧가루,\n매실액, 맛술을 넣어 재워둔다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00453_1.png'),(2466,481,2,'양파와 당근, 새송이, 대파는 입자있게\n다지고 마늘은 곱게 다져 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00453_2.png'),(2467,481,3,'재워둔 고기(①)에 파, 마늘, 양파,\n당근, 새송이를 넣고 골고루 섞는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00453_3.png'),(2468,481,4,'떡은 잘게 썰어 뜨거운 물에 잠시\n담그어 놓는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00453_4.png'),(2469,481,5,'섞어 놓은 고기(③)에 불려 놓은 떡을\n섞는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00453_5.png'),(2470,481,6,'고기반죽(⑤)을 조금씩 떼어 둥글게\n완자를 빚고, 팬에 기름을 둘러 굴리듯이\n굽는다. 냄비에 간장과 올리고당을 넣고\n끓이다가 구운 완자와 참기름을 넣어\n은근히 졸인 뒤 통깨를 얹어 완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00453_6.png'),(2471,482,1,'닭살은 한 번 정도 펴서 후춧가루를\n뿌려 사각지게 썰어 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00454_1.png'),(2472,482,2,'브로컬리는 살짝 데쳐 썰고, 양송이\n버섯은 껍질을 벗겨 두툼하게 썰어\n준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00454_2.png'),(2473,482,3,'파프리카와 토마토는 속씨를 제거하고\n사각으로 썰고, 당근, 양파, 표고버섯도\n사각지게 썰어 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00454_3.png'),(2474,482,4,'스파게티는 끓는 물에 소금을 넣고 약\n10분 정도 삶아 건져 올리브 오일을\n살짝 발라 준비한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00454_4.png'),(2475,482,5,'팬에 올리브 오일을 두르고, 따끈해지\n면, 닭살을 먼저 볶는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00454_5.png'),(2476,482,6,'닭고기살(⑤)에 준비한 채소(②,③)를\n넣고 살짝 볶다가 토마토 페이스트를\n넣어 다시 볶은 후 육수와 토마토소스,\n케첩, 생크림을 넣고 끓인 후 삶아놓은\n스파게티(④)를 넣고 한 번 더 끓여\n완성한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00454_6.png'),(2477,483,1,'배추, 오이는 얇게 채 썬 뒤 소금물에\n담가 절인 후 물기를 꼭 짜고,\n표고버섯은 채 썬 뒤 참기름과\n간장을 넣어 양념하고, 피망과\n당근은 얇게 채 썬다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00245_1.png'),(2478,483,2,'예열된 팬에 배추, 오이, 채 썬 피망,\n표고버섯 순으로 센 불에서 각각\n볶고, 당근은 물기를 제거한 뒤\n녹말가루를 묻혀 150℃로 예열한\n기름에 튀긴다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00245_2.png'),(2479,483,3,'닭가슴살은 얇게 저민 후\n후춧가루로 밑간을 한 뒤 볶아놓은\n채소를 올려 말아 계만두를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00245_3.png'),(2480,483,4,'찜기에 물과 마늘, 대파를 넣고\n육수를 내면서 예열하다가 김이\n오르면 말아놓은 계만두를 넣고\n약 8분 정도 찐다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00245_4.png'),(2481,483,5,'빠금장에 휘핑크림과 우유, 다진\n청양고추, 후춧가루, 참깨를 넣고\n끓여 빠금장소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00245_5.png'),(2482,483,6,'계만두에 튀긴 당근과 삶은\n메추리알을 곁들인 뒤 빠금장소스를\n곁들여 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00245_6.png'),(2483,484,1,'닭가슴살을 다져서 두부와 섞어준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00246_1.png'),(2484,484,2,'수삼과 파프리카를 채 썰고, 대추는\n돌려서 깎아준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00246_2.png'),(2485,484,3,'닭가슴살두부반죽을 얇게 편 후\n파프리카, 수삼, 대추를 올린 뒤\n풀리지 않게 종이포일로 만다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00246_3.png'),(2486,484,4,'김 오른 찜기에 20분간 쪄준다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00246_4.png'),(2487,484,5,'블루베리잼과 화이트와인을 졸인 뒤\n설탕을 넣고 블루베리소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00246_5.png'),(2488,484,6,'쪄낸 삼계선을 2㎝두께로 잘라 담고 블루베리소스를 곁들여 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00246_6.png'),(2489,485,1,'소를 고루 치대 반죽한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00247_1.png'),(2490,485,2,'표고버섯은 밑동을 제거한 뒤\n안쪽에 밀가루→달걀물 순서로\n바른 뒤 반죽을 넣고 달걀물을\n한 번 더 발라준 뒤 김 오른 찜기에\n15분간 찐다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00247_2.png'),(2491,485,3,'잣과 대추를 올리고 달걀물을 한 번\n더 바르고 3분간 더 찐다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00247_3.png'),(2492,485,4,'오렌지소스 재료를 팬에 넣고\n조린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00247_4.png'),(2493,485,5,'단호박은 얇게 썰어 노릇하게\n굽는다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00247_5.png'),(2494,485,6,'쇠고기표고찜에 오렌지소스를\n뿌리고 피클과 구운 단호박을\n곁들여 마무리한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00247_6.png'),(2495,486,1,'손질된 새우를 끓는 물에 데쳐 건진다.a','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00028_1.png'),(2496,486,2,'연두부, 달걀, 생크림, 설탕에 녹인 무염버터를 믹서에 넣고 간 뒤 새우(1)를 함께 섞어 그릇에 담는다.b','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00028_2.png'),(2497,486,3,'시금치를 잘게 다져 혼합물 그릇(2)에 뿌리고 찜기에 넣고 중간 불에서 10분 정도 찐다.c','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00028_3.png'),(2498,487,1,'부추는 깨끗이 씻어 물기를 제거하고, 5cm 길이로 썰고 부추에 날콩가루를 넣고 고루 섞이도록 버무린다.','http://www.foodsafetykorea.go.kr/uploadimg/20230206/20230206054820_1675673300714.jpg'),(2499,487,2,'찜기에 면보를 깔고 부추를 넣은 후 김이 오르게 쪄서 파랗게 익힌다.','http://www.foodsafetykorea.go.kr/uploadimg/20230206/20230206054834_1675673314720.jpg'),(2500,487,3,'저염간장에 다진 대파, 다진 마늘, 고춧가루, 요리당 , 참기름, 참깨를 섞어 양념장을 만들고 찐 부추는 그릇에 담아낸다.','http://www.foodsafetykorea.go.kr/uploadimg/20230206/20230206054908_1675673348152.jpg'),(2501,488,1,'물기를 빼고 2cm 정도의 크기로 썰은 부추와 양파를 양념장에 섞어 양념속을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00031_1.png'),(2502,488,2,'깨끗이 씻은 방울토마토는 꼭지를 떼고 윗부분에 칼로 십자모양으로 칼집을 낸다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00031_4.png'),(2503,488,3,'칼집을 낸 방울토마토에 양념속을 사이사이에 넣어 버무린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00031_5.png'),(2504,489,1,'사과, 순두부를 믹서에 넣고 곱게 갈아 소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00032_1.png'),(2505,489,2,'오이는 소금으로 문질러 씻어 반을 갈라 씨를 제거하고 어슷썰기를 한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00032_2.png'),(2506,489,3,'썰어 놓은 오이에 순두부사과 소스를 넣고 버무린 후 다진 땅콩을 뿌려 마무리 한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00032_3.png'),(2507,490,1,'북어채를 잘게 손으로 찢어 찬물에 헹구어 준비한 후 양파, 표고버섯, 사과는 채 썰고 새우는 등쪽의 두세 마디에 꼬챙이를 넣어 내장을 뺀 후 헹군다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00033_2.png'),(2508,490,2,'찬물에 북어채, 새우, 표고버섯, 양파를 넣고 20분 정도 끓인 후 사과를 넣어 북어의 씁쓸한 맛을 없앤다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00033_3.png'),(2509,490,3,'그릇에 담아낸다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00033_5.png'),(2510,491,1,'손질된 새우를 끓는 물에 데쳐 건진다.a','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00028_1.png'),(2511,491,2,'연두부, 달걀, 생크림, 설탕에 녹인 무염버터를 믹서에 넣고 간 뒤 새우(1)를 함께 섞어 그릇에 담는다.b','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00028_2.png'),(2512,491,3,'시금치를 잘게 다져 혼합물 그릇(2)에 뿌리고 찜기에 넣고 중간 불에서 10분 정도 찐다.c','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00028_3.png'),(2513,492,1,'부추는 깨끗이 씻어 물기를 제거하고, 5cm 길이로 썰고 부추에 날콩가루를 넣고 고루 섞이도록 버무린다.','http://www.foodsafetykorea.go.kr/uploadimg/20230206/20230206054820_1675673300714.jpg'),(2514,492,2,'찜기에 면보를 깔고 부추를 넣은 후 김이 오르게 쪄서 파랗게 익힌다.','http://www.foodsafetykorea.go.kr/uploadimg/20230206/20230206054834_1675673314720.jpg'),(2515,492,3,'저염간장에 다진 대파, 다진 마늘, 고춧가루, 요리당 , 참기름, 참깨를 섞어 양념장을 만들고 찐 부추는 그릇에 담아낸다.','http://www.foodsafetykorea.go.kr/uploadimg/20230206/20230206054908_1675673348152.jpg'),(2516,493,1,'물기를 빼고 2cm 정도의 크기로 썰은 부추와 양파를 양념장에 섞어 양념속을 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00031_1.png'),(2517,493,2,'깨끗이 씻은 방울토마토는 꼭지를 떼고 윗부분에 칼로 십자모양으로 칼집을 낸다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00031_4.png'),(2518,493,3,'칼집을 낸 방울토마토에 양념속을 사이사이에 넣어 버무린다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00031_5.png'),(2519,494,1,'사과, 순두부를 믹서에 넣고 곱게 갈아 소스를 만든다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00032_1.png'),(2520,494,2,'오이는 소금으로 문질러 씻어 반을 갈라 씨를 제거하고 어슷썰기를 한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00032_2.png'),(2521,494,3,'썰어 놓은 오이에 순두부사과 소스를 넣고 버무린 후 다진 땅콩을 뿌려 마무리 한다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00032_3.png'),(2522,495,1,'북어채를 잘게 손으로 찢어 찬물에 헹구어 준비한 후 양파, 표고버섯, 사과는 채 썰고 새우는 등쪽의 두세 마디에 꼬챙이를 넣어 내장을 뺀 후 헹군다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00033_2.png'),(2523,495,2,'찬물에 북어채, 새우, 표고버섯, 양파를 넣고 20분 정도 끓인 후 사과를 넣어 북어의 씁쓸한 맛을 없앤다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00033_3.png'),(2524,495,3,'그릇에 담아낸다.','http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00033_5.png');
